type SharedSessionLog = Arc<Mutex<session_log::SessionLog>>;

/// Session log directory for the panic hook to write panic.log into.
/// Set once when a session starts; read by the panic hook on crash.
static PANIC_LOG_DIR: std::sync::OnceLock<PathBuf> = std::sync::OnceLock::new();

/// Shared slot for JSON-mode approval responses.
/// The stdin reader stores approval senders here; the agent loop awaits them.
type JsonApprovalSlot =
    Arc<Mutex<Option<(u64, tokio::sync::oneshot::Sender<event::ApprovalResponse>)>>>;

fn new_json_approval_slot() -> JsonApprovalSlot {
    Arc::new(Mutex::new(None))
}

/// Helper to write to the session log without propagating errors.
fn slog(log: &SharedSessionLog, f: impl FnOnce(&mut session_log::SessionLog)) {
    if let Ok(mut l) = log.lock() {
        f(&mut l);
    }
}

fn session_log_id(session_log: &SharedSessionLog) -> Option<String> {
    session_log
        .lock()
        .ok()
        .map(|log| log.session_id().to_string())
        .filter(|id| !id.is_empty())
}

fn external_resume_session_for_startup(
    backend: Option<&external_agent::AgentBackend>,
    flags: &CliFlags,
    intendant_session_id: Option<&str>,
) -> Option<String> {
    external_resume_session_for_startup_in_home(
        &platform::home_dir(),
        backend,
        flags,
        intendant_session_id,
    )
}

fn external_resume_session_for_startup_in_home(
    home: &Path,
    backend: Option<&external_agent::AgentBackend>,
    flags: &CliFlags,
    intendant_session_id: Option<&str>,
) -> Option<String> {
    let backend = backend?;
    let intendant_session_id = intendant_session_id
        .map(str::trim)
        .filter(|id| !id.is_empty())?;
    let requested_resume_token = flags
        .resume_id
        .as_deref()
        .or(flags.continue_last.then_some(intendant_session_id))?;
    let token = session_supervisor::effective_external_resume_token_in_home(
        home,
        backend.as_short_str(),
        intendant_session_id,
        requested_resume_token,
        false,
    );
    (!token.trim().is_empty()).then_some(token)
}

/// Rehydrate the persisted per-session agent config for a CLI startup resume
/// (`--resume` / `--continue` with an external backend) and lay it over
/// `project`, mirroring the precedence `SessionSupervisor::resume_session`
/// applies on the daemon path:
///
///   explicit overrides > persisted per-session config > global/TOML project
///
/// Returns the effective per-session overrides so callers can forward the
/// fields that don't live in the project (`codex_service_tier`,
/// `codex_home`) to the agent, or `None` when there is nothing to apply
/// (fresh startup, no resume token, or no persisted config).
fn apply_startup_external_resume_config(
    backend: &external_agent::AgentBackend,
    project: &mut Project,
    intendant_session_id: Option<&str>,
    resume_session: Option<&str>,
) -> Option<session_config::SessionAgentConfig> {
    apply_startup_external_resume_config_in_home(
        &platform::home_dir(),
        backend,
        project,
        intendant_session_id,
        resume_session,
        // No per-field agent CLI flags exist today (only `--agent <BACKEND>`),
        // so there are no explicit overrides to protect at startup. If such
        // flags are added, build this from them (see `session_config::from_wire`)
        // so they keep winning over the persisted per-session config.
        session_config::SessionAgentConfig::default(),
    )
}

fn apply_startup_external_resume_config_in_home(
    home: &Path,
    backend: &external_agent::AgentBackend,
    project: &mut Project,
    intendant_session_id: Option<&str>,
    resume_session: Option<&str>,
    explicit_overrides: session_config::SessionAgentConfig,
) -> Option<session_config::SessionAgentConfig> {
    let resume_token = resume_session
        .map(str::trim)
        .filter(|token| !token.is_empty())?;
    let session_id = intendant_session_id
        .map(str::trim)
        .filter(|id| !id.is_empty())
        .unwrap_or(resume_token);
    let mut config = explicit_overrides;
    if let Some(persisted) = session_config::load_for_resume(
        home,
        backend.as_short_str(),
        session_id,
        Some(resume_token),
    ) {
        config.merge_missing_from(persisted);
    }
    if config.is_empty() {
        return None;
    }
    session_config::apply_to_project(project, backend, &config);
    Some(config)
}

fn emit_external_session_identity(
    bus: &EventBus,
    session_id: Option<String>,
    source: &str,
    backend_session_id: &str,
) {
    let Some(session_id) = session_id.filter(|id| !id.trim().is_empty()) else {
        return;
    };
    bus.send(AppEvent::SessionIdentity {
        session_id,
        source: source.to_string(),
        backend_session_id: backend_session_id.to_string(),
    });
}

fn record_external_done_and_round_inline(
    session_log: &SharedSessionLog,
    enabled: bool,
    session_id: Option<&str>,
    message: Option<&str>,
    round: usize,
    turns_in_round: usize,
) {
    if !enabled {
        return;
    }
    slog(session_log, |log| {
        log.done_signal_for_session(session_id, message);
        log.round_complete(round, turns_in_round);
    });
}

fn record_external_round_inline(
    session_log: &SharedSessionLog,
    enabled: bool,
    round: usize,
    turns_in_round: usize,
) {
    if !enabled {
        return;
    }
    slog(session_log, |log| log.round_complete(round, turns_in_round));
}

fn external_rollback_turn_in_progress(err: &CallerError) -> bool {
    let CallerError::ExternalAgent(message) = err else {
        return false;
    };
    message
        .to_ascii_lowercase()
        .contains("cannot rollback while a turn is in progress")
}

fn event_targets_session(target: &Option<String>, session_id: &Option<String>) -> bool {
    match target {
        Some(target) => session_id.as_deref() == Some(target.as_str()),
        None => true,
    }
}

fn event_targets_session_or_alias(
    target: &Option<String>,
    session_id: &Option<String>,
    alias_session_id: &Option<String>,
) -> bool {
    match target {
        Some(target) => {
            session_id.as_deref() == Some(target.as_str())
                || alias_session_id.as_deref() == Some(target.as_str())
        }
        None => true,
    }
}

fn event_targets_external_session_or_side(
    target: &Option<String>,
    session_id: &Option<String>,
    alias_session_id: &Option<String>,
    side_threads: &HashMap<String, String>,
) -> bool {
    match target {
        Some(target) => {
            event_targets_session_or_alias(&Some(target.clone()), session_id, alias_session_id)
                || side_threads.contains_key(target)
        }
        None => true,
    }
}

fn event_targets_external_session_or_optional_side(
    target: &Option<String>,
    session_id: &Option<String>,
    alias_session_id: &Option<String>,
    side_threads: Option<&HashMap<String, String>>,
) -> bool {
    match side_threads {
        Some(side_threads) => event_targets_external_session_or_side(
            target,
            session_id,
            alias_session_id,
            side_threads,
        ),
        None => event_targets_session_or_alias(target, session_id, alias_session_id),
    }
}

#[derive(Clone, Copy, Debug, Eq, PartialEq)]
enum ExternalSteerTargetKind {
    Primary,
    Side,
}

fn resolve_external_steer_target_session(
    target: &Option<String>,
    session_id: &Option<String>,
    alias_session_id: &Option<String>,
    side_threads: Option<&HashMap<String, String>>,
) -> Option<(Option<String>, ExternalSteerTargetKind)> {
    match target.as_deref() {
        Some(target) if side_threads.is_some_and(|threads| threads.contains_key(target)) => {
            Some((Some(target.to_string()), ExternalSteerTargetKind::Side))
        }
        Some(_) if event_targets_session_or_alias(target, session_id, alias_session_id) => {
            Some((session_id.clone(), ExternalSteerTargetKind::Primary))
        }
        Some(_) => None,
        None => Some((session_id.clone(), ExternalSteerTargetKind::Primary)),
    }
}

fn external_steer_queue_reason(agent_name: &str, err: &CallerError) -> String {
    let unsupported = match err {
        CallerError::ExternalAgent(message) => {
            message.contains("mid-turn steering not supported")
                || message.contains("steering not supported")
        }
        _ => false,
    };
    if unsupported {
        format!("{agent_name} doesn't support mid-turn steering ({err}); queued as follow-up")
    } else {
        format!("{agent_name} native mid-turn steering failed ({err}); queued as follow-up")
    }
}

fn external_steer_error_is_no_active_turn(err: &CallerError) -> bool {
    match err {
        CallerError::ExternalAgent(message) => message.contains("no active turn"),
        _ => false,
    }
}

fn external_steer_targets_idle_side_thread(
    target_kind: ExternalSteerTargetKind,
    target_session_id: Option<&str>,
    active_side_turns: &HashSet<String>,
) -> bool {
    target_kind == ExternalSteerTargetKind::Side
        && target_session_id.is_some_and(|id| !active_side_turns.contains(id))
}

/// Build the [`peer::AuthRequirements`] this daemon advertises in
/// its own Agent Card from the project's `[server.auth]` config and
/// the access cert dir.
///
/// Resolution rules:
///
/// - `transport`:
///   - `advertised_transport = "none"` (default) → [`peer::TransportAuth::None`]
///   - `"mutual-tls"` → [`peer::TransportAuth::MutualTls`]
///   - `"pin-self-cert"` → read this daemon's own `server.crt` from
///     the access cert dir, compute its SHA-256 fingerprint, embed it
///     in [`peer::TransportAuth::PinnedMutualTls`]. Errors if no
///     cert is present (operator forgot to run `intendant access
///     setup`).
///   - any other value → config error
/// - `application`:
///   - `bearer_token = "..."` set → `Some(Bearer { hint, rotation_url: None })`
///     where `hint` documents where the token comes from so peers
///     can give operators a useful "configure me" message
///   - unset → `None`
///
/// Called once per spawn_web_gateway invocation, at daemon startup.
/// Errors propagate as `CallerError::Config` so the operator sees
/// a clean startup failure rather than a silent misconfigure.
fn build_local_advertised_auth(
    server_auth: &project::ServerAuthConfig,
    cert_dir: &std::path::Path,
) -> Result<peer::AuthRequirements, CallerError> {
    let transport = match server_auth.advertised_transport.as_str() {
        "none" => peer::TransportAuth::None,
        "mutual-tls" => peer::TransportAuth::MutualTls,
        "pin-self-cert" => {
            // `pin-self-cert` reads the local server cert produced by
            // `intendant access setup`. The cert store is per-user and is
            // consumed directly by native `--tls` / `--mtls`.
            let fp = access::certs::read_server_cert_fingerprint(cert_dir).ok_or_else(|| {
                CallerError::Config(format!(
                    "[server.auth] advertised_transport = \"pin-self-cert\" requires \
                     a local server cert at {}/server.crt — run `intendant access setup` \
                     first, or change advertised_transport to \"none\" / \"mutual-tls\"",
                    cert_dir.display()
                ))
            })?;
            peer::TransportAuth::PinnedMutualTls {
                server_cert_fingerprints: vec![fp],
            }
        }
        other => {
            return Err(CallerError::Config(format!(
                "[server.auth] advertised_transport = {other:?} is not a valid value \
                 (accepted: \"none\", \"mutual-tls\", \"pin-self-cert\")"
            )));
        }
    };
    let application = server_auth
        .bearer_token
        .as_ref()
        .map(|_| peer::ApplicationAuth::Bearer {
            hint: Some("[server.auth] bearer_token".to_string()),
            rotation_url: None,
        });
    Ok(peer::AuthRequirements {
        transport,
        application,
    })
}

/// Resolve the advertise-URL list passed to `spawn_web_gateway`,
/// applying CLI > config > auto-detect precedence.
///
/// - If `--advertise-url` was given (one or more times), the CLI list
///   wins entirely. The operator at the command line beats the
///   operator at the config file.
/// - Otherwise, if `[server.advertise]` in `intendant.toml` is non-
///   empty, that list is used.
/// - If both are empty, an empty `Vec` is returned, which signals
///   `spawn_web_gateway` to fall back to its single-URL auto-detection
///   from the listener's bind address (the historical behavior).
///
/// Returns owned `String`s so the caller can move the list directly
/// into `spawn_web_gateway` without an extra clone.
fn resolve_advertise_urls_from_flags_and_config(
    flags: &CliFlags,
    project: &Project,
) -> Vec<String> {
    if !flags.advertise_urls.is_empty() {
        flags.advertise_urls.clone()
    } else {
        project.config.server.advertise.clone()
    }
}

/// Build a peer registry for this daemon and hydrate it from the
/// `[[peer]]` sections in `intendant.toml`.
///
/// Spawns the durable log writer task (appending
/// `TaggedPeerEvent`s as JSONL to `<log_dir>/peers.jsonl`) and
/// creates a [`crate::peer::PeerRegistry`] wired to its sender.
/// Each config entry fires a background `add_peer` task so
/// slow/unreachable peers don't block daemon startup — the
/// registry's own reconnect state machine handles those
/// asynchronously once the card fetch returns.
///
/// The returned registry is cheaply cloneable (`Arc`-backed) and
/// gets passed into `spawn_web_gateway` so the `/api/peers`
/// handlers can inspect and mutate the same store. The log
/// writer's join handle is intentionally dropped — the writer
/// exits cleanly when all its senders go away (peer actors +
/// registry clones), and we don't currently have an explicit
/// daemon shutdown path that would await it.
fn build_and_hydrate_peer_registry(
    log_dir: &Path,
    peer_configs: &[project::PeerConfig],
) -> peer::PeerRegistry {
    let log_path = log_dir.join("peers.jsonl");
    let (log_tx, _log_handle) = peer::spawn_peer_log_writer(log_path);
    let registry = peer::PeerRegistry::new(log_tx);
    for cfg in peer_configs {
        let registry_for_task = registry.clone();
        let card_url = cfg.card_url.clone();
        let bearer_token = cfg.bearer_token.clone();
        let pinned_fingerprints = cfg.pinned_fingerprints.clone();
        let browser_tcp_via_url = cfg.browser_tcp_via_url.clone();
        let explicit_client_identity = match peer_client_identity_from_config(cfg) {
            Ok(identity) => identity,
            Err(e) => {
                eprintln!(
                    "intendant: failed to register peer from intendant.toml \
                     ({card_url}): {e}"
                );
                continue;
            }
        };
        tokio::spawn(async move {
            // Vec::new() for via_urls (could be threaded through
            // PeerConfig later if config-driven via overrides become
            // a need; per-peer dashboard adds already use the via_urls
            // field on AddPeerRequest). pinned_fingerprints, when
            // non-empty, replaces the card's auth.transport with
            // PinnedMutualTls — operator distrusts the card's claim
            // and pins against fingerprints they got out-of-band.
            // browser_tcp_via_url, when set, overrides the dashboard's
            // default `d.ws_url` fallback when opening WebRTC display
            // — used when the browser and primary can't share the
            // same URL (primary-side localhost tunnel, split
            // browser/primary machines, etc.).
            if let Err(e) = registry_for_task
                .add_peer_with_credentials_and_client_identity(
                    &card_url,
                    Vec::new(),
                    bearer_token,
                    pinned_fingerprints,
                    browser_tcp_via_url,
                    explicit_client_identity,
                )
                .await
            {
                eprintln!(
                    "intendant: failed to register peer from intendant.toml \
                     ({card_url}): {e}"
                );
            }
        });
    }
    registry
}

fn peer_client_identity_from_config(
    cfg: &project::PeerConfig,
) -> Result<Option<peer::transport::tls_client::ClientIdentityPaths>, CallerError> {
    match (&cfg.client_cert, &cfg.client_key) {
        (Some(cert), Some(key)) => Ok(Some(peer::transport::tls_client::ClientIdentityPaths {
            cert_path: PathBuf::from(cert),
            key_path: PathBuf::from(key),
        })),
        (None, None) => Ok(None),
        (Some(_), None) | (None, Some(_)) => Err(CallerError::Config(format!(
            "[[peer]] card_url={} must set client_cert and client_key together",
            cfg.card_url
        ))),
    }
}

/// Emit a "[runtime] Task dispatched" log entry from a backend task acceptance
/// point. Writes to the session log on disk and broadcasts a `LogEntry` event
/// for external consumers (web dashboard, control socket).
///
/// This is the single source of truth for the dispatch log line: it lives in
/// the backend (where the task is actually accepted for processing) rather
/// than in any frontend, so the log is consistent across TUI, headless, and
/// daemon modes regardless of which interface originated the task.
fn emit_task_dispatched_log(
    bus: &EventBus,
    session_log: &SharedSessionLog,
    task: &str,
    attachment_count: usize,
) {
    let suffix = if attachment_count > 0 {
        format!(
            " with {} attachment{}",
            attachment_count,
            if attachment_count == 1 { "" } else { "s" }
        )
    } else {
        String::new()
    };
    let message = format!(
        "[runtime] Task dispatched{}: {}",
        suffix,
        types::truncate_str(task, 80)
    );
    slog(session_log, |l| l.info(&message));
    bus.send(AppEvent::LogEntry {
        session_id: None,
        level: "info".to_string(),
        source: "system".to_string(),
        content: message,
        turn: None,
    });
}

fn emit_user_message_log(
    bus: &EventBus,
    session_log: &SharedSessionLog,
    session_id: Option<&str>,
    user_turn_index: Option<u32>,
    user_turn_revision: Option<u32>,
    replacement_for_user_turn_index: Option<u32>,
    text: &str,
) {
    let text = text.trim();
    if text.is_empty() {
        return;
    }
    slog(session_log, |l| l.info(&format!("[user] {}", text)));
    bus.send(AppEvent::UserMessageLog {
        session_id: session_id.map(str::to_string),
        content: text.to_string(),
        user_turn_index,
        user_turn_revision,
        replacement_for_user_turn_index,
    });
}

fn emit_external_session_loop_error(
    bus: &EventBus,
    session_log: &SharedSessionLog,
    session_id: Option<&str>,
    source: &str,
    message: String,
) {
    slog(session_log, |l| l.warn(&message));
    bus.send(AppEvent::LogEntry {
        session_id: session_id.map(str::to_string),
        level: "warn".to_string(),
        source: source.to_string(),
        content: message.clone(),
        turn: None,
    });
    bus.send(AppEvent::LoopError(message));
}

fn json_string_field(v: &serde_json::Value, key: &str) -> Option<String> {
    v.get(key).and_then(|x| x.as_str()).map(str::to_string)
}

fn collect_jsonl_files(root: &Path, out: &mut Vec<PathBuf>) {
    let Ok(entries) = std::fs::read_dir(root) else {
        return;
    };
    for entry in entries.flatten() {
        let path = entry.path();
        if path.is_dir() {
            collect_jsonl_files(&path, out);
        } else if path
            .file_name()
            .and_then(|n| n.to_str())
            .map(|name| name.ends_with(".jsonl"))
            .unwrap_or(false)
        {
            out.push(path);
        }
    }
}

fn codex_session_file_id(path: &Path) -> Option<String> {
    let contents = std::fs::read_to_string(path).ok()?;
    for line in contents.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            continue;
        }
        let Ok(obj) = serde_json::from_str::<serde_json::Value>(trimmed) else {
            continue;
        };
        if obj.get("type").and_then(|v| v.as_str()) == Some("session_meta") {
            return obj
                .get("payload")
                .and_then(|payload| json_string_field(payload, "id"));
        }
    }
    None
}

fn find_codex_session_file_for_main(home: &Path, session_id: &str) -> Option<PathBuf> {
    let codex = std::env::var_os("CODEX_HOME")
        .map(PathBuf::from)
        .filter(|p| !p.as_os_str().is_empty())
        .unwrap_or_else(|| home.join(".codex"));
    let mut files = Vec::new();
    collect_jsonl_files(&codex.join("sessions"), &mut files);
    collect_jsonl_files(&codex.join("archived_sessions"), &mut files);
    files
        .into_iter()
        .find(|path| codex_session_file_id(path).as_deref() == Some(session_id))
}

fn codex_message_content_text(content: &serde_json::Value) -> Option<String> {
    match content {
        serde_json::Value::String(s) => Some(s.clone()),
        serde_json::Value::Array(items) => {
            let parts: Vec<String> = items
                .iter()
                .filter_map(|item| {
                    item.get("text")
                        .and_then(|v| v.as_str())
                        .or_else(|| item.get("content").and_then(|v| v.as_str()))
                        .map(str::to_string)
                })
                .collect();
            if parts.is_empty() {
                None
            } else {
                Some(parts.join("\n"))
            }
        }
        _ => None,
    }
}

fn codex_payload_user_text(payload: &serde_json::Value) -> Option<String> {
    if payload.get("type").and_then(|v| v.as_str()) != Some("message") {
        return None;
    }
    if payload.get("role").and_then(|v| v.as_str()) != Some("user") {
        return None;
    }
    let text = codex_message_content_text(payload.get("content")?)?;
    if is_codex_injected_user_text_for_main(&text) {
        None
    } else {
        Some(text)
    }
}

#[derive(Debug, Clone, Default)]
struct UserTurnRevisionState {
    active_count: u32,
    latest_revision_by_turn: HashMap<u32, u32>,
    active_revision_by_turn: HashMap<u32, u32>,
}

impl UserTurnRevisionState {
    fn active_count(&self) -> u32 {
        self.active_count
    }

    fn active_revision(&self, user_turn_index: u32) -> Option<u32> {
        self.active_revision_by_turn.get(&user_turn_index).copied()
    }

    fn seed_active_turns_to(&mut self, active_count: u32) {
        while self.active_count < active_count {
            self.record_next_turn();
        }
    }

    fn record_next_turn(&mut self) -> (u32, u32) {
        let user_turn_index = self.active_count.saturating_add(1);
        let revision = self.record_active_turn(user_turn_index);
        self.active_count = user_turn_index;
        (user_turn_index, revision)
    }

    fn record_active_turn(&mut self, user_turn_index: u32) -> u32 {
        let next_revision = self
            .latest_revision_by_turn
            .get(&user_turn_index)
            .copied()
            .unwrap_or(0)
            .saturating_add(1);
        self.latest_revision_by_turn
            .insert(user_turn_index, next_revision);
        self.active_revision_by_turn
            .insert(user_turn_index, next_revision);
        self.active_count = self.active_count.max(user_turn_index);
        next_revision
    }

    fn rewind_last_turns(&mut self, turns_to_drop: u32) {
        if turns_to_drop == 0 || self.active_count == 0 {
            return;
        }
        let first_user_turn_index = self
            .active_count
            .saturating_sub(turns_to_drop)
            .saturating_add(1);
        self.rewind_from_turn(first_user_turn_index);
    }

    fn rewind_from_turn(&mut self, first_user_turn_index: u32) {
        if first_user_turn_index == 0 || first_user_turn_index > self.active_count {
            return;
        }
        for turn in first_user_turn_index..=self.active_count {
            self.active_revision_by_turn.remove(&turn);
        }
        self.active_count = first_user_turn_index.saturating_sub(1);
    }

    fn validate_expected_revision(
        &self,
        user_turn_index: u32,
        expected_revision: Option<u32>,
    ) -> Result<(), String> {
        let Some(expected_revision) = expected_revision else {
            return Err(format!(
                "Cannot edit user turn {}; missing active-message revision",
                user_turn_index
            ));
        };
        match self.active_revision(user_turn_index) {
            Some(active_revision) if active_revision == expected_revision => Ok(()),
            Some(active_revision) => Err(format!(
                "Cannot edit user turn {}; the displayed message revision {} is stale (active revision is {})",
                user_turn_index, expected_revision, active_revision
            )),
            None => Err(format!(
                "Cannot edit user turn {}; that message is no longer active context",
                user_turn_index
            )),
        }
    }
}

fn is_codex_injected_user_text_for_main(text: &str) -> bool {
    let trimmed = text.trim_start();
    trimmed.starts_with("# AGENTS.md instructions for ")
        || trimmed.starts_with("<turn_aborted>")
        || trimmed.starts_with("<subagent_notification>")
        || trimmed.starts_with("<environment_context>")
        || trimmed.starts_with("<task-notification>")
        || trimmed.starts_with("<command-name>")
        || trimmed.starts_with("<command-message>")
        || trimmed.starts_with("<local-command-stdout>")
        || trimmed.starts_with("<bash-input>")
        || trimmed.starts_with("<bash-stdout>")
        || trimmed.starts_with("<bash-stderr>")
        || trimmed.starts_with("<user_shell_command>")
}

fn codex_user_turn_state_from_history(session_id: &str) -> Option<UserTurnRevisionState> {
    let home = PathBuf::from(std::env::var("HOME").unwrap_or_else(|_| "/tmp".to_string()));
    let path = find_codex_session_file_for_main(&home, session_id)?;
    codex_user_turn_state_from_history_file(&path)
}

fn codex_user_turn_state_from_history_file(path: &Path) -> Option<UserTurnRevisionState> {
    let contents = std::fs::read_to_string(path).ok()?;
    let mut saw_user_message_event = false;
    let mut event_state = UserTurnRevisionState::default();
    let mut fallback_state = UserTurnRevisionState::default();

    for line in contents.lines() {
        let Ok(obj) = serde_json::from_str::<serde_json::Value>(line) else {
            continue;
        };
        match obj.get("type").and_then(|v| v.as_str()).unwrap_or("") {
            "event_msg" => {
                let Some(payload) = obj.get("payload") else {
                    continue;
                };
                match payload.get("type").and_then(|v| v.as_str()).unwrap_or("") {
                    "user_message" => {
                        saw_user_message_event = true;
                        event_state.record_next_turn();
                    }
                    "thread_rolled_back" => {
                        let turns = payload
                            .get("num_turns")
                            .and_then(|v| v.as_u64())
                            .unwrap_or(0) as u32;
                        event_state.rewind_last_turns(turns);
                        fallback_state.rewind_last_turns(turns);
                    }
                    _ => {}
                }
            }
            "response_item" => {
                if obj
                    .get("payload")
                    .and_then(codex_payload_user_text)
                    .is_some()
                {
                    fallback_state.record_next_turn();
                }
            }
            _ => {}
        }
    }

    Some(if saw_user_message_event {
        event_state
    } else {
        fallback_state
    })
}

/// Resolve external agent backend from an explicit override, falling back to
/// the project config's `agent.default_backend` setting.
fn resolve_agent_backend_from_config(
    explicit: Option<external_agent::AgentBackend>,
    project: &Project,
) -> Option<external_agent::AgentBackend> {
    explicit.or_else(|| {
        project
            .config
            .agent
            .default_backend
            .as_ref()
            .and_then(|s| external_agent::AgentBackend::from_str_loose(s))
    })
}

/// Structural equality for `CodexRuntimeConfig`. The struct itself doesn't
/// derive `PartialEq` because it's a public API surface and we don't want to
/// commit to field-by-field equality semantics for external callers; inside
/// the daemon loop we just need to detect drift across tasks, so we compare
/// the Codex-locked fields explicitly. Any change here that affects the
/// spawned Codex thread (sandbox, approvals, model, reasoning effort, tool
/// set, sandbox permissions) has to force a rebuild because Codex latches
/// those at `thread/start`.
fn codex_runtime_config_equal(
    a: &control_plane::CodexRuntimeConfig,
    b: &control_plane::CodexRuntimeConfig,
) -> bool {
    a.command == b.command
        && a.managed_command == b.managed_command
        && a.sandbox == b.sandbox
        && a.approval_policy == b.approval_policy
        && a.model == b.model
        && a.reasoning_effort == b.reasoning_effort
        && a.service_tier == b.service_tier
        && a.web_search == b.web_search
        && a.network_access == b.network_access
        && a.writable_roots == b.writable_roots
        && a.managed_context == b.managed_context
        && a.context_archive == b.context_archive
}

/// Structural equality for `GeminiRuntimeConfig`. Every field here is a
/// command-line arg Gemini latches at process spawn, so any drift forces a
/// teardown + respawn on the next task.
fn gemini_runtime_config_equal(
    a: &control_plane::GeminiRuntimeConfig,
    b: &control_plane::GeminiRuntimeConfig,
) -> bool {
    a.model == b.model
        && a.approval_mode == b.approval_mode
        && a.sandbox == b.sandbox
        && a.extensions == b.extensions
        && a.allowed_mcp_servers == b.allowed_mcp_servers
        && a.include_directories == b.include_directories
        && a.debug == b.debug
}

fn normalize_diff_file_path(path: &str) -> Option<String> {
    let path = path.split('\t').next().unwrap_or(path).trim();
    if path == "/dev/null" {
        return None;
    }
    // Strip exactly one git-style `a/` or `b/` prefix. Codex sometimes
    // produces `b//home/...` (double slash) for absolute paths; that
    // becomes `/home/...` after the single-prefix strip.
    let path = path
        .strip_prefix("a/")
        .or_else(|| path.strip_prefix("b/"))
        .unwrap_or(path);
    if path.is_empty() {
        return None;
    }
    Some(path.to_string())
}

/// Extract file paths from a unified-diff header. Reads `+++ b/<path>` lines
/// (git-style), with `--- a/<path>` used as a fallback for pure-delete diffs
/// where the `+++` side is `/dev/null`. Deduplicates while preserving order.
///
/// Used when the external agent's own `files_changed` list is empty, which
/// has been observed for Codex's `turn/diff/updated` notifications in
/// practice — the wire protocol carries the paths only inside the diff body.
fn parse_diff_file_paths(unified_diff: &str) -> Vec<String> {
    let mut out: Vec<String> = Vec::new();
    for line in unified_diff.lines() {
        let path = if let Some(rest) = line.strip_prefix("+++ ") {
            rest
        } else if let Some(rest) = line.strip_prefix("--- ") {
            rest
        } else {
            continue;
        };
        if let Some(path) = normalize_diff_file_path(path) {
            if !out.iter().any(|p| p == &path) {
                out.push(path);
            }
        }
    }
    out
}

fn diff_line_text(line: &str) -> &str {
    line.trim_end_matches(['\r', '\n'])
}

fn is_unified_file_boundary(lines: &[&str], idx: usize) -> bool {
    let line = diff_line_text(lines[idx]);
    line.starts_with("diff --git ")
        || (line.starts_with("--- ")
            && lines
                .get(idx + 1)
                .is_some_and(|next| diff_line_text(next).starts_with("+++ ")))
}

fn split_unified_diff_by_file(unified_diff: &str) -> Vec<(String, String)> {
    if unified_diff.trim().is_empty() {
        return Vec::new();
    }

    let mut lines: Vec<&str> = unified_diff.split_inclusive('\n').collect();
    if lines.is_empty() {
        lines.push(unified_diff);
    }

    let mut starts: Vec<usize> = lines
        .iter()
        .enumerate()
        .filter_map(|(idx, line)| {
            diff_line_text(line)
                .starts_with("diff --git ")
                .then_some(idx)
        })
        .collect();
    if starts.is_empty() {
        for idx in 0..lines.len() {
            if is_unified_file_boundary(&lines, idx) {
                starts.push(idx);
            }
        }
    }
    if starts.is_empty() {
        let files = parse_diff_file_paths(unified_diff);
        return files
            .into_iter()
            .next()
            .map(|path| vec![(path, unified_diff.to_string())])
            .unwrap_or_default();
    }

    let mut out = Vec::new();
    for (i, start) in starts.iter().copied().enumerate() {
        let end = starts.get(i + 1).copied().unwrap_or(lines.len());
        let block = lines[start..end].concat();
        if let Some(path) = parse_diff_file_paths(&block).into_iter().next() {
            out.push((path, block));
        }
    }
    out
}

fn external_diff_log_body(message: &str) -> Option<&str> {
    if !message.starts_with("External agent diff") {
        return None;
    }
    let first_line_end = message.find('\n')?;
    let body = &message[first_line_end + 1..];
    if body.contains("diff --git ") || body.contains("--- ") || body.contains("@@ ") {
        Some(body)
    } else {
        None
    }
}

fn parse_session_diff_file_paths(log_dir: &Path) -> Vec<String> {
    let Ok(contents) = std::fs::read_to_string(log_dir.join("session.jsonl")) else {
        return Vec::new();
    };

    let mut out = Vec::new();
    for line in contents.lines() {
        let Ok(value) = serde_json::from_str::<serde_json::Value>(line) else {
            continue;
        };
        let Some(message) = value.get("message").and_then(|v| v.as_str()) else {
            continue;
        };
        let Some(diff_body) = external_diff_log_body(message) else {
            continue;
        };
        for path in parse_diff_file_paths(diff_body) {
            if !out.iter().any(|p| p == &path) {
                out.push(path);
            }
        }
    }
    out
}

fn resolve_diff_file_path(project_root: &Path, display_path: &str) -> Option<PathBuf> {
    let path = Path::new(display_path);
    if path.is_absolute() {
        return (path.starts_with(project_root)
            || path.starts_with("/tmp")
            || path.starts_with("/private/tmp"))
        .then(|| path.to_path_buf());
    }

    if path.components().any(|component| {
        matches!(
            component,
            std::path::Component::ParentDir
                | std::path::Component::RootDir
                | std::path::Component::Prefix(_)
        )
    }) {
        return None;
    }

    Some(project_root.join(path))
}

fn read_diff_file_text(project_root: &Path, display_path: &str) -> Option<Option<String>> {
    let path = resolve_diff_file_path(project_root, display_path)?;
    match std::fs::read_to_string(path) {
        Ok(text) => Some(Some(text)),
        Err(err) if err.kind() == std::io::ErrorKind::NotFound => Some(None),
        Err(_) => None,
    }
}

struct ExternalDiffDelta {
    files_changed: Vec<String>,
    unified_diff: String,
}

#[derive(Default)]
struct ExternalDiffDeltaTracker {
    snapshots: HashMap<String, Option<String>>,
}

impl ExternalDiffDeltaTracker {
    fn seed_current_paths<'a>(
        &mut self,
        project_root: &Path,
        paths: impl IntoIterator<Item = &'a str>,
    ) {
        for path in paths {
            let Some(path) = normalize_diff_file_path(path) else {
                continue;
            };
            let Some(current) = read_diff_file_text(project_root, &path) else {
                continue;
            };
            self.snapshots.insert(path, current);
        }
    }

    fn seed_from_session_log(&mut self, project_root: &Path, log_dir: &Path) {
        let paths = parse_session_diff_file_paths(log_dir);
        self.seed_current_paths(project_root, paths.iter().map(String::as_str));
    }

    fn delta(
        &mut self,
        project_root: &Path,
        files_changed: &[String],
        unified_diff: &str,
    ) -> Option<ExternalDiffDelta> {
        let mut ordered_paths = Vec::new();
        let mut seen = HashSet::new();
        let mut block_by_path = HashMap::new();

        for (path, block) in split_unified_diff_by_file(unified_diff) {
            if seen.insert(path.clone()) {
                ordered_paths.push(path.clone());
            }
            block_by_path.entry(path).or_insert(block);
        }

        for path in files_changed {
            if let Some(path) = normalize_diff_file_path(path) {
                if seen.insert(path.clone()) {
                    ordered_paths.push(path);
                }
            }
        }

        let mut previously_tracked: Vec<String> = self.snapshots.keys().cloned().collect();
        previously_tracked.sort();
        for path in previously_tracked {
            if seen.insert(path.clone()) {
                ordered_paths.push(path);
            }
        }

        let mut delta_diff = String::new();
        let mut delta_files = Vec::new();

        for path in ordered_paths {
            let current = read_diff_file_text(project_root, &path).flatten();
            let maybe_delta = if let Some(previous) = self.snapshots.get(&path) {
                if previous == &current {
                    None
                } else {
                    Some(file_watcher::compute_unified_diff(
                        previous.as_deref().unwrap_or(""),
                        current.as_deref().unwrap_or(""),
                        &path,
                    ))
                }
            } else if let Some(block) = block_by_path.get(&path) {
                Some(block.clone())
            } else {
                current
                    .as_ref()
                    .map(|text| file_watcher::compute_unified_diff("", text, &path))
            };

            self.snapshots.insert(path.clone(), current);

            let Some(file_delta) = maybe_delta else {
                continue;
            };
            if file_delta.trim().is_empty() {
                continue;
            }
            delta_files.push(path);
            delta_diff.push_str(&file_delta);
            if !delta_diff.ends_with('\n') {
                delta_diff.push('\n');
            }
        }

        if delta_diff.trim().is_empty() {
            None
        } else {
            Some(ExternalDiffDelta {
                files_changed: delta_files,
                unified_diff: delta_diff,
            })
        }
    }
}

/// Resolve external agent backend from shared state (written by the web UI),
/// falling back to the project config default.
async fn resolve_agent_backend(
    shared: &Arc<tokio::sync::RwLock<Option<external_agent::AgentBackend>>>,
    project: &Project,
) -> Option<external_agent::AgentBackend> {
    resolve_agent_backend_from_config(shared.read().await.clone(), project)
}

fn codex_context_trace_dir(
    session_log: &SharedSessionLog,
    context_archive: &str,
) -> (Option<PathBuf>, bool) {
    match project::normalize_codex_context_archive(context_archive).as_str() {
        "off" => (None, false),
        "exact" => (
            session_log
                .lock()
                .ok()
                .map(|log| log.dir().join("model-request-traces")),
            false,
        ),
        _ => {
            let session = session_log_id(session_log)
                .unwrap_or_else(|| uuid::Uuid::new_v4().simple().to_string());
            let dir = std::env::temp_dir()
                .join("intendant-context-traces")
                .join(format!("{session}-{}", uuid::Uuid::new_v4().simple()));
            (Some(dir), true)
        }
    }
}

/// Construct, initialize, and start a thread for an external agent backend.
///
/// Returns the agent, thread handle, and event receiver. The caller owns the
/// agent lifetime and is responsible for sending messages and draining events.
async fn create_external_agent(
    backend: &external_agent::AgentBackend,
    project: &Project,
    session_log: &SharedSessionLog,
    web_port: Option<u16>,
    resume_session: Option<String>,
    mcp_session_id: Option<String>,
    codex_service_tier: Option<String>,
    codex_home: Option<String>,
) -> Result<
    (
        Box<dyn external_agent::ExternalAgent>,
        external_agent::AgentThread,
        tokio::sync::mpsc::UnboundedReceiver<external_agent::AgentEvent>,
    ),
    CallerError,
> {
    use external_agent::{AgentBackend, AgentConfig};

    let mcp_session_id = mcp_session_id.or_else(|| session_log_id(session_log));

    let (mut agent, config): (Box<dyn external_agent::ExternalAgent>, AgentConfig) = match backend {
        AgentBackend::Codex => {
            let cfg = &project.config.agent.codex;
            let sandbox_mode = project::normalize_sandbox_mode(&cfg.sandbox);
            let reasoning_effort =
                project::normalize_reasoning_effort(cfg.reasoning_effort.as_deref());
            let codex_managed_context =
                project::codex_managed_context_enabled(&cfg.managed_context);
            let context_archive = project::normalize_codex_context_archive(&cfg.context_archive);
            let (request_trace_dir, request_trace_temporary) =
                codex_context_trace_dir(session_log, &context_archive);
            let codex_home = codex_home
                .as_deref()
                .and_then(|home| crate::session_config::normalize_codex_home(Some(home)))
                .or_else(crate::session_config::effective_codex_home)
                .map(PathBuf::from);
            let opts = external_agent::codex::CodexAgentOptions {
                reasoning_effort: reasoning_effort.clone(),
                web_search: cfg.web_search,
                network_access: cfg.network_access,
                writable_roots: cfg.writable_roots.clone(),
                managed_context: codex_managed_context,
            };
            // Managed sessions spawn the Intendant-aware fork when one is
            // configured (`codex.managed_command`); vanilla sessions and
            // legacy configs use `codex.command`.
            let agent = Box::new(external_agent::codex::CodexAgent::with_options(
                cfg.effective_command(codex_managed_context),
                cfg.model.clone(),
                cfg.approval_policy.clone(),
                sandbox_mode.clone(),
                web_port,
                opts,
            ));
            let config = AgentConfig {
                model: cfg.model.clone(),
                working_dir: project.root.clone(),
                request_trace_dir,
                request_trace_temporary,
                context_archive,
                approval_policy: cfg.approval_policy.clone(),
                sandbox: sandbox_mode,
                reasoning_effort,
                service_tier: codex_service_tier
                    .or_else(|| project::normalize_codex_service_tier(cfg.service_tier.as_deref())),
                web_search: cfg.web_search,
                network_access: cfg.network_access,
                writable_roots: cfg.writable_roots.clone(),
                codex_managed_context,
                web_port,
                mcp_session_id: mcp_session_id.clone(),
                resume_session: resume_session.clone(),
                codex_home,
            };
            (agent, config)
        }
        AgentBackend::GeminiCli => {
            let cfg = &project.config.agent.gemini_cli;
            let approval_mode = project::normalize_gemini_approval_mode(&cfg.approval_mode);
            let launch = external_agent::gemini::GeminiLaunchConfig {
                model: cfg.model.clone(),
                approval_mode: approval_mode.clone(),
                sandbox: cfg.sandbox,
                extensions: cfg.extensions.clone(),
                allowed_mcp_servers: cfg.allowed_mcp_servers.clone(),
                include_directories: cfg.include_directories.clone(),
                debug: cfg.debug,
            };
            let agent = Box::new(external_agent::gemini::GeminiAgent::new(
                cfg.command.clone(),
                launch,
                web_port,
            ));
            let config = AgentConfig {
                model: cfg.model.clone(),
                working_dir: project.root.clone(),
                request_trace_dir: None,
                request_trace_temporary: false,
                context_archive: "off".to_string(),
                // `AgentConfig.approval_policy` is Codex's `-a` flag; for
                // Gemini we reuse the field as the ACP approval hint so the
                // sandbox/prompt layer can adjust if needed. Storing the
                // normalized Gemini approval mode keeps the two backends
                // schema-compatible at the trait level.
                approval_policy: approval_mode,
                sandbox: String::new(),
                reasoning_effort: None,
                service_tier: None,
                web_search: false,
                network_access: false,
                writable_roots: Vec::new(),
                codex_managed_context: false,
                web_port,
                mcp_session_id: None,
                resume_session: resume_session.clone(),
                codex_home: None,
            };
            (agent, config)
        }
        AgentBackend::ClaudeCode => {
            let cfg = &project.config.agent.claude_code;
            let agent = Box::new(external_agent::claude_code::ClaudeCodeAgent::new(
                cfg.command.clone(),
                cfg.model.clone(),
                cfg.permission_mode.clone(),
                cfg.allowed_tools.clone(),
                web_port,
            ));
            let config = AgentConfig {
                model: cfg.model.clone(),
                working_dir: project.root.clone(),
                request_trace_dir: None,
                request_trace_temporary: false,
                context_archive: "off".to_string(),
                approval_policy: cfg.permission_mode.clone(),
                sandbox: String::new(),
                reasoning_effort: None,
                service_tier: None,
                web_search: false,
                network_access: false,
                writable_roots: Vec::new(),
                codex_managed_context: false,
                web_port,
                mcp_session_id: None,
                resume_session: resume_session.clone(),
                codex_home: None,
            };
            (agent, config)
        }
    };

    let event_rx = agent.initialize(config).await?;
    slog(session_log, |l| l.debug("External agent initialized"));

    let thread = agent.start_thread().await?;
    slog(session_log, |l| {
        l.debug(&format!("External agent thread: {}", thread.thread_id))
    });

    Ok((agent, thread, event_rx))
}

/// Configuration for `drain_external_agent_events`.
struct DrainConfig<'a> {
    bus: &'a EventBus,
    session_id: Option<String>,
    alias_session_id: Option<String>,
    /// The backend (Codex) thread id of THIS conversation, when the caller
    /// holds the live `AgentThread`. Conversations are named inconsistently
    /// across paths — the CLI external-agent loop uses `session_id` = thread
    /// id with the Intendant session id as the alias, while the daemon's
    /// persistent dispatch loop uses `session_id` = Intendant session id with
    /// the thread id as the alias — so a thread action that targets this
    /// conversation by either name resolves its `threadId` from this field
    /// rather than guessing which of the two ids the backend understands.
    backend_thread_id: Option<String>,
    autonomy: SharedAutonomy,
    session_log: &'a SharedSessionLog,
    project_root: &'a Path,
    log_dir: &'a Path,
    approval_registry: &'a event::ApprovalRegistry,
    json_approval: Option<&'a JsonApprovalSlot>,
    /// Web dashboard port when serving (`--web`). `Some` means an interactive
    /// frontend exists, so external-agent approval requests are surfaced to
    /// the gate rather than auto-denied as if truly headless.
    web_port: Option<u16>,
    agent_source: Option<String>,
    /// When true, `ToolStarted` just increments the turn counter without
    /// emitting `AgentStarted`. The presence path sets this to avoid
    /// duplicating the model reasoning that's already shown via ModelResponse.
    suppress_agent_started: bool,
    /// Supervised external sessions have their own session log in addition to
    /// the daemon's root log writer. Persist model responses here too so
    /// per-session replay does not depend on the root session log.
    persist_model_responses_inline: bool,
    /// When true and no `json_approval` slot is set, auto-deny approval
    /// requests (headless mode with no interactive input).
    headless: bool,
    /// Shared context-injection queue. Fallback target when the backend
    /// does not support mid-turn steering — queued items are drained on
    /// the next turn's follow-up message path.
    context_injection: &'a event::ContextInjectionQueue,
}

struct PendingRuntimeSteer {
    session_id: Option<String>,
    id: String,
    text: String,
}

fn steer_id_has_been_handled(
    handled_steer_ids: &std::collections::HashSet<String>,
    id: &str,
) -> bool {
    !id.trim().is_empty() && handled_steer_ids.contains(id)
}

fn mark_steer_id_handled(handled_steer_ids: &mut std::collections::HashSet<String>, id: &str) {
    if !id.trim().is_empty() {
        handled_steer_ids.insert(id.to_string());
    }
}

fn pending_runtime_steer_targets_session(
    pending: &PendingRuntimeSteer,
    session_id: &Option<String>,
) -> bool {
    pending.session_id.as_deref() == session_id.as_deref()
}

fn queued_steer_targets_session(
    injection: &event::ContextInjection,
    session_id: Option<&str>,
    alias_session_id: Option<&str>,
) -> bool {
    if injection.steer_id.is_none() {
        return false;
    }
    let Some(target) = injection
        .target_session_id
        .as_deref()
        .map(str::trim)
        .filter(|target| !target.is_empty())
    else {
        return true;
    };
    session_id == Some(target) || alias_session_id == Some(target)
}

fn has_queued_steers_for_session(
    context_injection: &event::ContextInjectionQueue,
    session_id: Option<&str>,
    alias_session_id: Option<&str>,
) -> bool {
    context_injection
        .lock()
        .map(|queue| {
            queue.iter().any(|injection| {
                queued_steer_targets_session(injection, session_id, alias_session_id)
            })
        })
        .unwrap_or(false)
}

fn queued_steer_matches_cancel(
    injection: &event::ContextInjection,
    session_id: Option<&str>,
    alias_session_id: Option<&str>,
    steer_id: Option<&str>,
) -> bool {
    if !queued_steer_targets_session(injection, session_id, alias_session_id) {
        return false;
    }
    match steer_id.map(str::trim).filter(|id| !id.is_empty()) {
        Some(steer_id) => injection.steer_id.as_deref() == Some(steer_id),
        None => true,
    }
}

fn cancel_queued_steers_for_session(
    context_injection: &event::ContextInjectionQueue,
    bus: &EventBus,
    session_id: Option<&str>,
    alias_session_id: Option<&str>,
    steer_id: Option<&str>,
    reason: &str,
) -> usize {
    let mut cancelled = 0usize;
    if let Ok(mut q) = context_injection.lock() {
        let mut kept = Vec::with_capacity(q.len());
        for inj in q.drain(..) {
            if queued_steer_matches_cancel(&inj, session_id, alias_session_id, steer_id) {
                cancelled += 1;
                bus.send(AppEvent::SteerCancelled {
                    session_id: inj
                        .target_session_id
                        .as_deref()
                        .map(str::to_string)
                        .or_else(|| session_id.map(str::to_string)),
                    id: inj.steer_id.clone().unwrap_or_default(),
                    reason: reason.to_string(),
                });
            } else {
                kept.push(inj);
            }
        }
        *q = kept;
    }
    cancelled
}

fn flush_pending_runtime_steers_for_session(
    bus: &EventBus,
    pending_runtime_steers: &mut std::collections::VecDeque<PendingRuntimeSteer>,
    session_id: &Option<String>,
) -> usize {
    let mut delivered = 0usize;
    let mut retained = std::collections::VecDeque::with_capacity(pending_runtime_steers.len());
    while let Some(pending) = pending_runtime_steers.pop_front() {
        if pending_runtime_steer_targets_session(&pending, session_id) {
            delivered += 1;
            bus.send(AppEvent::SteerDelivered {
                session_id: pending.session_id,
                id: pending.id,
                mid_turn: true,
            });
        } else {
            retained.push_back(pending);
        }
    }
    *pending_runtime_steers = retained;
    delivered
}

fn cancel_pending_runtime_steers_for_session(
    bus: &EventBus,
    pending_runtime_steers: &mut std::collections::VecDeque<PendingRuntimeSteer>,
    session_id: Option<&str>,
    alias_session_id: Option<&str>,
    steer_id: Option<&str>,
    reason: &str,
) -> usize {
    let mut cancelled = 0usize;
    let mut retained = std::collections::VecDeque::with_capacity(pending_runtime_steers.len());
    while let Some(pending) = pending_runtime_steers.pop_front() {
        let target_matches = match session_id {
            Some(session_id) => {
                pending.session_id.as_deref() == Some(session_id)
                    || pending.session_id.as_deref() == alias_session_id
            }
            None => true,
        };
        let id_matches = match steer_id.map(str::trim).filter(|id| !id.is_empty()) {
            Some(steer_id) => pending.id == steer_id,
            None => true,
        };
        if target_matches && id_matches {
            cancelled += 1;
            bus.send(AppEvent::SteerCancelled {
                session_id: pending.session_id,
                id: pending.id,
                reason: reason.to_string(),
            });
        } else {
            retained.push_back(pending);
        }
    }
    *pending_runtime_steers = retained;
    cancelled
}

fn flush_pending_runtime_steers_for_model_checkpoint(
    bus: &EventBus,
    pending_runtime_steers: &mut std::collections::VecDeque<PendingRuntimeSteer>,
    session_id: &Option<String>,
) -> usize {
    flush_pending_runtime_steers_for_session(bus, pending_runtime_steers, session_id)
}

fn mark_pending_runtime_steers_delivered_at_model_checkpoint(
    config: &DrainConfig<'_>,
    pending_runtime_steers: &mut std::collections::VecDeque<PendingRuntimeSteer>,
    agent_name: &str,
) {
    // Codex records turn/steer input in its conversation log, but does not
    // reliably echo it back through the app-server stream as a userMessage.
    // Once the model produces new output, the runtime checkpoint happened and
    // the accepted steer should no longer stay pinned in the dashboard queue.
    let delivered = flush_pending_runtime_steers_for_model_checkpoint(
        config.bus,
        pending_runtime_steers,
        &config.session_id,
    );
    if delivered > 0 {
        slog(config.session_log, |l| {
            l.info(&format!(
                "Marked {} accepted {} steer(s) delivered at model checkpoint",
                delivered, agent_name
            ))
        });
    }
}

const EXTERNAL_CONTEXT_SNAPSHOT_INTERVAL: Duration = Duration::from_secs(1);
const EXTERNAL_TOOL_OUTPUT_ACTIVITY_INLINE_LIMIT: usize = 4 * 1024;
const EXTERNAL_TOOL_OUTPUT_ACTIVITY_HEAD_LIMIT: usize = 2 * 1024;
const EXTERNAL_TOOL_OUTPUT_ACTIVITY_TAIL_LIMIT: usize = 2 * 1024;
const EXTERNAL_TOOL_OUTPUT_ACTIVITY_TOTAL_LIMIT: usize = 24 * 1024;
const EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_HEAD_LIMIT: usize = 1024;
const EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TAIL_LIMIT: usize = 1024;
const EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TOTAL_LIMIT: usize = 4 * 1024;
const EXTERNAL_TOOL_SOURCE_OUTPUT_DETECTION_MIN_BYTES: usize = 2 * 1024;
const EXTERNAL_TOOL_SOURCE_OUTPUT_DETECTION_LINE_LIMIT: usize = 200;
const EXTERNAL_TOOL_PREVIEW_ACTIVITY_LIMIT: usize = 512;
const EXTERNAL_TOOL_FAILURE_REPEAT_LIMIT: usize = 2;

#[derive(Default)]
struct ExternalContextSnapshotState {
    emitted_keys: std::collections::HashSet<u64>,
    last_error: Option<String>,
}

#[derive(Debug, Clone, Default)]
struct ExternalToolOutputLimiter {
    items: std::collections::HashMap<String, ExternalToolOutputState>,
    total_emitted_bytes: usize,
    total_truncated: bool,
    source_emitted_bytes: usize,
    source_truncated: bool,
}

#[derive(Debug, Clone, Default)]
struct ExternalToolOutputState {
    seen_bytes: usize,
    emitted_head_bytes: usize,
    tail: String,
    omitting: bool,
    omission_notice_emitted: bool,
    source_like: bool,
    source_signals: ExternalToolSourceSignals,
}

#[derive(Debug, Clone, Default)]
struct ExternalToolSourceSignals {
    observed_lines: usize,
    non_empty_lines: usize,
    code_like_lines: usize,
    markup_like_lines: usize,
    style_like_lines: usize,
    structural_lines: usize,
    source_hint_lines: usize,
}

#[derive(Debug, Clone, Default)]
struct ExternalToolFailureLogLimiter {
    counts: std::collections::HashMap<String, usize>,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct ManagedContextRewindOnlyPressure {
    used_tokens: u64,
    rewind_only_limit: u64,
    hard_context_window: Option<u64>,
    status: &'static str,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
struct ManagedContextDensityPressure {
    used_tokens: u64,
    recommended_rewind_limit: u64,
    rewind_only_limit: u64,
    hard_context_window: Option<u64>,
}

impl ExternalToolOutputLimiter {
    fn filter(&mut self, item_id: &str, text: String) -> Option<String> {
        if text.is_empty() {
            return None;
        }

        if self.total_emitted_bytes >= EXTERNAL_TOOL_OUTPUT_ACTIVITY_TOTAL_LIMIT {
            if self.total_truncated {
                return None;
            }
            self.total_truncated = true;
            return Some(external_tool_output_total_truncation_notice());
        }

        let key = if item_id.is_empty() {
            "<unknown>".to_string()
        } else {
            item_id.to_string()
        };
        let item_source_like;
        let mut source_backcharge_bytes = 0usize;
        let emit = {
            let state = self.items.entry(key).or_default();
            let was_source_like = state.source_like;
            let previously_emitted_head_bytes = state.emitted_head_bytes;
            state.seen_bytes = state.seen_bytes.saturating_add(text.len());
            state.source_signals.observe(&text);
            if state
                .source_signals
                .looks_like_large_source(state.seen_bytes)
            {
                state.source_like = true;
            }
            if !was_source_like && state.source_like {
                source_backcharge_bytes = previously_emitted_head_bytes;
            }
            item_source_like = state.source_like;

            if state.omitting {
                state.push_tail(&text);
                None
            } else {
                let head_limit = if state.source_like {
                    EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_HEAD_LIMIT
                } else if state.emitted_head_bytes == 0
                    && text.len() > EXTERNAL_TOOL_OUTPUT_ACTIVITY_INLINE_LIMIT
                {
                    EXTERNAL_TOOL_OUTPUT_ACTIVITY_HEAD_LIMIT
                } else {
                    EXTERNAL_TOOL_OUTPUT_ACTIVITY_INLINE_LIMIT
                };
                let remaining_for_head = head_limit.saturating_sub(state.emitted_head_bytes);
                if text.len() <= remaining_for_head {
                    state.emitted_head_bytes += text.len();
                    Some(text)
                } else {
                    let split_at = char_boundary_at_or_before(&text, remaining_for_head);
                    let mut out = text[..split_at].to_string();
                    state.emitted_head_bytes += split_at;
                    state.omitting = true;
                    state.omission_notice_emitted = true;
                    state.push_tail(&text[split_at..]);
                    out.push_str(&external_tool_output_omission_start_notice(
                        state.emitted_head_bytes,
                    ));
                    Some(out)
                }
            }
        };
        self.charge_prior_source_output(source_backcharge_bytes);
        emit.and_then(|out| self.emit_with_caps(out, item_source_like))
    }

    fn complete(&mut self, item_id: &str) -> Option<String> {
        let key = if item_id.is_empty() {
            "<unknown>"
        } else {
            item_id
        };
        let state = self.items.remove(key)?;
        if !state.omission_notice_emitted {
            return None;
        }
        let tail = state.tail;
        let tail_bytes = tail.len();
        let omitted_middle_bytes = state
            .seen_bytes
            .saturating_sub(state.emitted_head_bytes)
            .saturating_sub(tail_bytes);
        let mut out = external_tool_output_omission_tail_notice(
            state.seen_bytes,
            state.emitted_head_bytes,
            tail_bytes,
            omitted_middle_bytes,
        );
        out.push_str(&tail);
        self.emit_with_caps(out, state.source_like)
    }

    fn emit_with_caps(&mut self, text: String, source_like: bool) -> Option<String> {
        if source_like {
            self.emit_with_source_cap(text)
                .and_then(|out| self.emit_with_total_cap(out))
        } else {
            self.emit_with_total_cap(text)
        }
    }

    fn charge_prior_source_output(&mut self, bytes: usize) {
        if bytes == 0
            || self.source_emitted_bytes >= EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TOTAL_LIMIT
        {
            return;
        }
        self.source_emitted_bytes = self
            .source_emitted_bytes
            .saturating_add(bytes)
            .min(EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TOTAL_LIMIT);
    }

    fn emit_with_source_cap(&mut self, text: String) -> Option<String> {
        if text.is_empty() {
            return None;
        }
        if self.source_emitted_bytes >= EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TOTAL_LIMIT {
            if self.source_truncated {
                return None;
            }
            self.source_truncated = true;
            return Some(external_tool_source_output_total_truncation_notice());
        }

        let remaining =
            EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TOTAL_LIMIT - self.source_emitted_bytes;
        if text.len() <= remaining {
            self.source_emitted_bytes += text.len();
            return Some(text);
        }

        let split_at = char_boundary_at_or_before(&text, remaining);
        let mut out = text[..split_at].to_string();
        self.source_emitted_bytes = EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TOTAL_LIMIT;
        self.source_truncated = true;
        out.push_str(&external_tool_source_output_total_truncation_notice());
        Some(out)
    }

    fn emit_with_total_cap(&mut self, text: String) -> Option<String> {
        if text.is_empty() {
            return None;
        }
        if self.total_emitted_bytes >= EXTERNAL_TOOL_OUTPUT_ACTIVITY_TOTAL_LIMIT {
            if self.total_truncated {
                return None;
            }
            self.total_truncated = true;
            return Some(external_tool_output_total_truncation_notice());
        }

        let remaining = EXTERNAL_TOOL_OUTPUT_ACTIVITY_TOTAL_LIMIT - self.total_emitted_bytes;
        if text.len() <= remaining {
            self.total_emitted_bytes += text.len();
            return Some(text);
        }

        let split_at = char_boundary_at_or_before(&text, remaining);
        let mut out = text[..split_at].to_string();
        self.total_emitted_bytes = EXTERNAL_TOOL_OUTPUT_ACTIVITY_TOTAL_LIMIT;
        self.total_truncated = true;
        out.push_str(&external_tool_output_total_truncation_notice());
        Some(out)
    }
}

impl ExternalToolOutputState {
    fn push_tail(&mut self, text: &str) {
        if text.is_empty() {
            return;
        }
        self.tail.push_str(text);
        let tail_limit = if self.source_like {
            EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TAIL_LIMIT
        } else {
            EXTERNAL_TOOL_OUTPUT_ACTIVITY_TAIL_LIMIT
        };
        if self.tail.len() <= tail_limit {
            return;
        }
        let trim_to = self.tail.len().saturating_sub(tail_limit);
        let split_at = char_boundary_at_or_after(&self.tail, trim_to);
        self.tail.drain(..split_at);
    }
}

impl ExternalToolSourceSignals {
    fn observe(&mut self, text: &str) {
        if text.is_empty()
            || self.observed_lines >= EXTERNAL_TOOL_SOURCE_OUTPUT_DETECTION_LINE_LIMIT
        {
            return;
        }

        for line in text.lines() {
            if self.observed_lines >= EXTERNAL_TOOL_SOURCE_OUTPUT_DETECTION_LINE_LIMIT {
                break;
            }
            self.observed_lines += 1;
            let trimmed = external_tool_output_strip_source_line_prefix(line.trim());
            if trimmed.is_empty() {
                continue;
            }

            self.non_empty_lines += 1;
            let code_like = external_tool_source_line_has_code_token(trimmed);
            let markup_like = external_tool_source_line_has_markup_token(trimmed);
            let style_like = external_tool_source_line_has_style_token(trimmed);
            if code_like {
                self.code_like_lines += 1;
            }
            if markup_like {
                self.markup_like_lines += 1;
            }
            if style_like {
                self.style_like_lines += 1;
            }
            if code_like || markup_like || style_like {
                self.source_hint_lines += 1;
            }
            if external_tool_source_line_has_structural_token(trimmed) {
                self.structural_lines += 1;
            }
        }
    }

    fn looks_like_large_source(&self, seen_bytes: usize) -> bool {
        if seen_bytes <= EXTERNAL_TOOL_SOURCE_OUTPUT_DETECTION_MIN_BYTES
            || self.non_empty_lines < 24
        {
            return false;
        }

        let code_density = self.code_like_lines * 100 / self.non_empty_lines;
        let hint_density = self.source_hint_lines * 100 / self.non_empty_lines;
        let structural_density = self.structural_lines * 100 / self.non_empty_lines;
        (self.code_like_lines >= 8 && self.structural_lines >= 8 && code_density >= 20)
            || (self.markup_like_lines >= 8 && self.structural_lines >= 8)
            || (self.style_like_lines >= 8 && self.structural_lines >= 16)
            || (self.source_hint_lines >= 16
                && self.structural_lines >= 16
                && hint_density >= 35
                && structural_density >= 35)
    }
}

impl ExternalToolFailureLogLimiter {
    fn filter(&mut self, content: String) -> Option<String> {
        if content.trim().is_empty() {
            return None;
        }
        let key = external_tool_failure_repeat_key(&content);
        let count = self.counts.entry(key).or_insert(0);
        *count += 1;
        if *count <= EXTERNAL_TOOL_FAILURE_REPEAT_LIMIT {
            return Some(content);
        }
        if *count == EXTERNAL_TOOL_FAILURE_REPEAT_LIMIT + 1 {
            return Some(external_tool_failure_repeat_notice(&content));
        }
        None
    }
}

fn external_tool_output_omission_start_notice(shown_head_bytes: usize) -> String {
    format!(
        "\n\n[Intendant is omitting additional external tool output; shown first {shown_head_bytes} bytes, final tail will be shown when the tool completes]\n",
    )
}

fn external_tool_output_omission_tail_notice(
    total_bytes: usize,
    head_bytes: usize,
    tail_bytes: usize,
    omitted_middle_bytes: usize,
) -> String {
    format!(
        "\n\n[Intendant omitted {omitted_middle_bytes} bytes from the middle of {total_bytes} bytes of external tool output; shown head {head_bytes} bytes, final tail {tail_bytes} bytes]\n",
    )
}

fn external_tool_output_total_truncation_notice() -> String {
    format!(
        "\n\n[Intendant omitted additional external tool output after the {} KiB per-turn transcript cap]\n",
        EXTERNAL_TOOL_OUTPUT_ACTIVITY_TOTAL_LIMIT / 1024
    )
}

fn external_tool_source_output_total_truncation_notice() -> String {
    format!(
        "\n\n[Intendant omitted additional large source-like external tool output after the {} KiB per-turn source-output cap]\n",
        EXTERNAL_TOOL_SOURCE_OUTPUT_ACTIVITY_TOTAL_LIMIT / 1024
    )
}

fn external_tool_output_looks_like_large_source(text: &str) -> bool {
    let mut signals = ExternalToolSourceSignals::default();
    signals.observe(text);
    signals.looks_like_large_source(text.len())
}

fn external_tool_output_strip_source_line_prefix(line: &str) -> &str {
    let Some(rest) = external_tool_output_strip_numeric_line_prefix(line) else {
        return external_tool_output_strip_path_line_prefix(line).unwrap_or(line);
    };
    rest
}

fn external_tool_output_strip_path_line_prefix(line: &str) -> Option<&str> {
    let colon = line.find(':')?;
    let prefix = &line[..colon];
    if !(prefix.contains('/') || prefix.contains('.') || prefix.contains('\\')) {
        return None;
    }
    let rest = &line[colon + 1..];
    external_tool_output_strip_numeric_line_prefix(rest)
}

fn external_tool_output_strip_numeric_line_prefix(line: &str) -> Option<&str> {
    let digit_count = line.bytes().take_while(u8::is_ascii_digit).count();
    if digit_count == 0 || digit_count > 8 || digit_count >= line.len() {
        return None;
    }
    let separator = line.as_bytes()[digit_count];
    if !matches!(separator, b':' | b'\t' | b' ') {
        return None;
    }
    Some(line[digit_count + 1..].trim_start())
}

fn external_tool_source_line_has_code_token(line: &str) -> bool {
    const TOKENS: &[&str] = &[
        "fn ",
        "impl ",
        "pub ",
        "struct ",
        "enum ",
        "use ",
        "mod ",
        "let ",
        "const ",
        "static ",
        "async ",
        "await",
        "match ",
        "if ",
        "else",
        "for ",
        "while ",
        "return ",
        "function ",
        "class ",
        "import ",
        "export ",
        "type ",
        "interface ",
        "const ",
        "var ",
    ];
    TOKENS.iter().any(|token| line.contains(token))
}

fn external_tool_source_line_has_markup_token(line: &str) -> bool {
    let trimmed = line.trim_start();
    if trimmed.starts_with('<') && trimmed.contains('>') {
        return true;
    }
    trimmed.contains("</")
        || trimmed.contains("<div")
        || trimmed.contains("<span")
        || trimmed.contains("<button")
        || trimmed.contains("<script")
        || trimmed.contains("<style")
        || trimmed.contains("class=")
        || trimmed.contains(" id=")
}

fn external_tool_source_line_has_style_token(line: &str) -> bool {
    let trimmed = line.trim_start();
    (trimmed.contains(':') && trimmed.ends_with(';'))
        || (trimmed.ends_with('{')
            && (trimmed.starts_with('.')
                || trimmed.starts_with('#')
                || trimmed.starts_with('@')
                || trimmed.starts_with(":root")
                || trimmed.contains(" .")
                || trimmed.contains(" #")
                || trimmed.contains(" {")))
}

fn external_tool_source_line_has_structural_token(line: &str) -> bool {
    line.contains('{')
        || line.contains('}')
        || line.ends_with(';')
        || line.ends_with(',')
        || line.contains("=>")
        || (line.contains('<') && line.contains('>'))
}

fn char_boundary_at_or_before(text: &str, max_bytes: usize) -> usize {
    if max_bytes >= text.len() {
        return text.len();
    }
    let mut idx = max_bytes;
    while idx > 0 && !text.is_char_boundary(idx) {
        idx -= 1;
    }
    idx
}

fn char_boundary_at_or_after(text: &str, min_bytes: usize) -> usize {
    if min_bytes >= text.len() {
        return text.len();
    }
    let mut idx = min_bytes;
    while idx < text.len() && !text.is_char_boundary(idx) {
        idx += 1;
    }
    idx
}

fn summarize_external_activity_text(text: &str, max_bytes: usize) -> String {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return String::new();
    }

    let total_bytes = trimmed.len();
    let total_lines = trimmed.lines().count().max(1);
    let multiline = total_lines > 1;
    let candidate = if multiline {
        trimmed.lines().next().unwrap_or(trimmed).trim()
    } else {
        trimmed
    };
    let split_at = char_boundary_at_or_before(candidate, max_bytes);
    let mut summary = candidate[..split_at].trim_end().to_string();
    let truncated = multiline || split_at < candidate.len();
    if truncated {
        summary.push_str(" [truncated by Intendant; original ");
        summary.push_str(&total_bytes.to_string());
        summary.push_str(" bytes");
        if total_lines > 1 {
            summary.push_str(", ");
            summary.push_str(&total_lines.to_string());
            summary.push_str(" lines");
        }
        summary.push(']');
    }
    summary
}

fn external_tool_preview_text(tool_name: &str, preview: &str) -> Option<String> {
    let tool_name = tool_name.trim();
    let preview = summarize_external_activity_text(preview, EXTERNAL_TOOL_PREVIEW_ACTIVITY_LIMIT);
    match (tool_name.is_empty(), preview.is_empty()) {
        (true, true) => None,
        (true, false) => Some(preview),
        (false, true) => Some(tool_name.to_string()),
        (false, false) => Some(format!("{tool_name}: {preview}")),
    }
}

fn external_agent_log_source(agent_source: Option<&str>) -> String {
    agent_source
        .filter(|source| !source.trim().is_empty())
        .unwrap_or("worker")
        .to_string()
}

fn external_tool_failure_content(
    item_id: &str,
    message: &str,
    tool_preview: Option<&str>,
) -> String {
    let preview = tool_preview.map(str::trim).filter(|s| !s.is_empty());
    let command = preview
        .and_then(|preview| preview.strip_prefix("command: ").map(str::trim))
        .filter(|command| !command.is_empty());
    let label = if command.is_some() {
        "Command failed"
    } else {
        "Tool failed"
    };

    let mut content = if item_id.trim().is_empty() {
        format!("{label}: {message}")
    } else {
        format!("{label} ({item_id}): {message}")
    };

    if let Some(command) = command {
        content.push_str("\nCommand: ");
        content.push_str(&summarize_external_activity_text(
            command,
            EXTERNAL_TOOL_PREVIEW_ACTIVITY_LIMIT,
        ));
    } else if let Some(preview) = preview {
        content.push_str("\nTool: ");
        content.push_str(&summarize_external_activity_text(
            preview,
            EXTERNAL_TOOL_PREVIEW_ACTIVITY_LIMIT,
        ));
    }
    content
}

fn external_tool_failure_repeat_key(content: &str) -> String {
    let mut lines = content.lines();
    let first = normalize_external_tool_failure_first_line(lines.next().unwrap_or_default());
    let detail = lines
        .find(|line| {
            let trimmed = line.trim_start();
            trimmed.starts_with("Command: ") || trimmed.starts_with("Tool: ")
        })
        .map(str::trim)
        .unwrap_or_default();
    format!("{first}\n{detail}")
}

fn normalize_external_tool_failure_first_line(line: &str) -> String {
    let line = line.trim();
    for prefix in ["Command failed", "Tool failed"] {
        let Some(rest) = line.strip_prefix(prefix) else {
            continue;
        };
        let Some(rest) = rest.strip_prefix(" (") else {
            continue;
        };
        let Some((_, suffix)) = rest.split_once("): ") else {
            continue;
        };
        return format!("{prefix}: {suffix}");
    }
    line.to_string()
}

fn external_tool_failure_repeat_notice(content: &str) -> String {
    let summary = external_tool_failure_repeat_key(content)
        .lines()
        .filter(|line| !line.trim().is_empty())
        .collect::<Vec<_>>()
        .join(" | ");
    if summary.is_empty() {
        format!(
            "Repeated similar external tool failures suppressed after {} entries",
            EXTERNAL_TOOL_FAILURE_REPEAT_LIMIT
        )
    } else {
        format!(
            "Repeated similar external tool failures suppressed after {} entries: {}",
            EXTERNAL_TOOL_FAILURE_REPEAT_LIMIT, summary
        )
    }
}

/// Result of draining one batch of external agent events.
enum DrainOutcome {
    /// The agent's turn completed. The caller decides how to continue
    /// (e.g., wait for follow-up, emit DoneSignal, break inner loop).
    TurnCompleted {
        message: Option<String>,
        turns_in_round: usize,
    },
    /// The agent process terminated.
    Terminated {
        reason: String,
        exit_code: Option<i32>,
    },
    /// The event channel was closed unexpectedly.
    ChannelClosed,
    /// The backend finished a turn in a recoverable error state. The external
    /// agent process is still usable, but the caller must not immediately
    /// submit another ordinary continuation.
    RecoveryRequired {
        message: String,
        recovery_hint: Option<String>,
        turns_in_round: usize,
    },
    /// A user-requested interrupt completed cleanly. The agent was asked to
    /// cancel its turn (e.g. via `session/cancel` or `turn/interrupt`) and
    /// acknowledged with a terminal event. The caller should break its
    /// outer loop the same way it would for `TurnCompleted`, but MUST NOT
    /// wait for a follow-up message — the interrupt *is* the follow-up.
    Interrupted { reason: String },
    /// A model/tool requested context rewind during the active turn. The drain
    /// waits until the backend reports the turn complete, then returns this so
    /// the caller can apply the rollback while the thread is idle.
    ContextRewindRequested {
        request: ExternalContextRewindRequest,
        message: Option<String>,
        turns_in_round: usize,
        turn_stop_status: ManagedContextRewindTurnStopStatus,
    },
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ExternalBackendRecovery {
    message: String,
    recovery_hint: Option<String>,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ExternalContextRewindRequest {
    session_id: Option<String>,
    item_id: String,
    position: external_agent::RollbackAnchorPosition,
    reason: Option<String>,
    primer: Option<String>,
    preserve: Vec<String>,
    discard: Vec<String>,
    artifacts: Vec<String>,
    next_steps: Vec<String>,
    auto_resume: bool,
    require_density_improvement: bool,
    /// Supervisor-chosen anchor + synthetic primer (surgical recovery after
    /// the model exhausted its recovery step limit without rewinding).
    /// Marked on the durable rewind record.
    surgical: bool,
}

#[derive(Debug, Clone, PartialEq, Eq)]
enum ManagedContextRewindTurnStopStatus {
    NotRequested,
    StopRequestedNoToolObserved,
    StopRequestedCompleted {
        success: usize,
        failed: usize,
        cancelled: usize,
    },
    StopRequestedUnfinished {
        pending: usize,
        success: usize,
        failed: usize,
        cancelled: usize,
    },
    StopRequestFailed {
        message: String,
    },
}

impl Default for ManagedContextRewindTurnStopStatus {
    fn default() -> Self {
        Self::NotRequested
    }
}

#[derive(Debug, Default)]
struct ManagedContextRewindTurnStopTracker {
    stop_requested: bool,
    stop_error: Option<String>,
    pending_tools: HashSet<String>,
    success: usize,
    failed: usize,
    cancelled: usize,
}

impl ManagedContextRewindTurnStopTracker {
    fn request_stop(&mut self, active_tools: &HashSet<String>) {
        self.stop_requested = true;
        self.stop_error = None;
        self.pending_tools.extend(active_tools.iter().cloned());
    }

    fn fail_stop(&mut self, active_tools: &HashSet<String>, message: String) {
        self.stop_requested = true;
        self.stop_error = Some(message);
        self.pending_tools.extend(active_tools.iter().cloned());
    }

    fn record_tool_started(&mut self, item_id: &str) {
        if self.stop_requested && !item_id.trim().is_empty() {
            self.pending_tools.insert(item_id.to_string());
        }
    }

    fn record_tool_completed(
        &mut self,
        item_id: &str,
        status: &external_agent::ToolCompletionStatus,
    ) {
        if !self.stop_requested || !self.pending_tools.remove(item_id) {
            return;
        }
        match status {
            external_agent::ToolCompletionStatus::Success => self.success += 1,
            external_agent::ToolCompletionStatus::Failed { .. } => self.failed += 1,
            external_agent::ToolCompletionStatus::Cancelled => self.cancelled += 1,
        }
    }

    fn status(&self) -> ManagedContextRewindTurnStopStatus {
        if let Some(message) = self.stop_error.as_deref() {
            return ManagedContextRewindTurnStopStatus::StopRequestFailed {
                message: message.to_string(),
            };
        }
        if !self.stop_requested {
            return ManagedContextRewindTurnStopStatus::NotRequested;
        }
        let completed = self.success + self.failed + self.cancelled;
        if self.pending_tools.is_empty() {
            if completed == 0 {
                ManagedContextRewindTurnStopStatus::StopRequestedNoToolObserved
            } else {
                ManagedContextRewindTurnStopStatus::StopRequestedCompleted {
                    success: self.success,
                    failed: self.failed,
                    cancelled: self.cancelled,
                }
            }
        } else {
            ManagedContextRewindTurnStopStatus::StopRequestedUnfinished {
                pending: self.pending_tools.len(),
                success: self.success,
                failed: self.failed,
                cancelled: self.cancelled,
            }
        }
    }
}

#[derive(Debug, Default)]
struct CodexThreadActionDedupe {
    seen: HashSet<String>,
    order: VecDeque<String>,
}

impl CodexThreadActionDedupe {
    const MAX_SEEN: usize = 512;

    fn mark_seen(&mut self, request_id: &str) -> bool {
        if self.seen.contains(request_id) {
            return false;
        }
        let request_id = request_id.to_string();
        self.seen.insert(request_id.clone());
        self.order.push_back(request_id);
        while self.order.len() > Self::MAX_SEEN {
            if let Some(oldest) = self.order.pop_front() {
                self.seen.remove(&oldest);
            }
        }
        true
    }
}

impl ExternalContextRewindRequest {
    fn rendered_primer(
        &self,
        record_id: Option<&str>,
        carried_forward_prior_facts: Option<&str>,
    ) -> Option<String> {
        let primer = self.primer.as_deref()?.trim();
        if primer.is_empty() {
            return None;
        }
        let mut out = String::from(
            "<model_context_rewind_primer>\nHistory after the rewind target was pruned by rewind_context. Earlier history before the target is still present. Treat this primer as the carry-forward summary of only the pruned span.\n\n",
        );
        push_context_rewind_text_section(
            &mut out,
            "Reason",
            self.reason.as_deref().unwrap_or("context rewind"),
        );
        if let Some(record_id) = record_id.map(str::trim).filter(|id| !id.is_empty()) {
            push_context_rewind_text_section(&mut out, "Record id", record_id);
        }
        push_context_rewind_text_section(&mut out, "Primer", primer);
        push_context_rewind_list_section(&mut out, "Preserve", &self.preserve);
        push_context_rewind_list_section(&mut out, "Discard", &self.discard);
        push_context_rewind_list_section(&mut out, "Artifacts", &self.artifacts);
        push_context_rewind_list_section(&mut out, "Next steps", &self.next_steps);
        if let Some(facts) = carried_forward_prior_facts
            .map(str::trim)
            .filter(|facts| !facts.is_empty())
        {
            push_context_rewind_text_section(
                &mut out,
                "Previous managed-context primer facts not repeated above",
                facts,
            );
        }
        out.push_str("</model_context_rewind_primer>");
        Some(out)
    }

    fn resume_followup(&self) -> Option<FollowUpMessage> {
        if !self.auto_resume || self.primer.as_deref()?.trim().is_empty() {
            return None;
        }
        Some(FollowUpMessage::text(
            "<context_rewind_resumed>\nContinue from the model_context_rewind_primer that Intendant injected as developer context for the pruned span. Do not redo discarded work; continue with the next useful step.\n</context_rewind_resumed>"
                .to_string(),
        ))
    }

    fn target_label(&self) -> String {
        format!("{} item {}", self.position.as_str(), self.item_id)
    }
}

fn context_rewind_should_interrupt_active_turn(request: &ExternalContextRewindRequest) -> bool {
    // Model-origin managed rewinds must make the active Codex turn idle before
    // Intendant can apply the rewrite. Relying on the model to stop after the
    // tool result is brittle under context pressure: a single response can keep
    // issuing recovery tools and grow context before the scheduler runs.
    request.auto_resume
}

fn context_rewind_active_tool_defer_message(
    request: &ExternalContextRewindRequest,
    active_tool_count: usize,
    normal_tools_allowed: bool,
) -> Option<String> {
    if !request.auto_resume || active_tool_count == 0 || !normal_tools_allowed {
        return None;
    }
    Some(format!(
        "context rewind deferred to {}; {active_tool_count} active tool(s)/command(s) are still running and normal tools are currently allowed. Intendant did not stop the active turn or schedule the rewind. Wait for the active tool/command completion, then retry rewind_context with the same anchor and primer if cleanup is still needed.",
        request.target_label()
    ))
}

fn context_rewind_blocking_active_tool_count(
    active_tool_count: usize,
    action_origin: Option<&str>,
) -> usize {
    if action_origin == Some("mcp") {
        // The rewind_context MCP call is itself an active tool until this
        // handler returns; do not let it block its own scheduling.
        active_tool_count.saturating_sub(1)
    } else {
        active_tool_count
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ResolvedContextRewindAnchor {
    item_id: String,
}

impl ResolvedContextRewindAnchor {
    fn requested(item_id: &str) -> Self {
        Self {
            item_id: item_id.to_string(),
        }
    }

    fn target_label(&self, position: external_agent::RollbackAnchorPosition) -> String {
        format!("{} item {}", position.as_str(), self.item_id)
    }
}

fn push_context_rewind_text_section(out: &mut String, label: &str, value: &str) {
    let value = value.trim();
    if value.is_empty() {
        return;
    }
    out.push_str(label);
    out.push_str(":\n");
    out.push_str(value);
    out.push_str("\n\n");
}

fn push_context_rewind_list_section(out: &mut String, label: &str, values: &[String]) {
    if values.is_empty() {
        return;
    }
    out.push_str(label);
    out.push_str(":\n");
    for value in values {
        out.push_str("- ");
        out.push_str(value);
        out.push('\n');
    }
    out.push('\n');
}

fn clean_context_rewind_list(params: &serde_json::Value, key: &str) -> Vec<String> {
    params
        .get(key)
        .and_then(|value| value.as_array())
        .into_iter()
        .flatten()
        .filter_map(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
        .collect()
}

fn optional_trimmed_string(params: &serde_json::Value, key: &str) -> Option<String> {
    params
        .get(key)
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn context_rewind_anchor_item_id(params: &serde_json::Value) -> Option<String> {
    params
        .pointer("/anchor/itemId")
        .and_then(|value| value.as_str())
        .or_else(|| {
            params
                .pointer("/anchor/item_id")
                .and_then(|value| value.as_str())
        })
        .or_else(|| params.get("itemId").and_then(|value| value.as_str()))
        .or_else(|| params.get("item_id").and_then(|value| value.as_str()))
        .or_else(|| params.as_str())
        .map(str::trim)
        .filter(|item_id| !item_id.is_empty())
        .map(str::to_string)
}

fn context_rewind_anchor_position(
    params: &serde_json::Value,
) -> Option<external_agent::RollbackAnchorPosition> {
    match params
        .pointer("/anchor/position")
        .and_then(|value| value.as_str())
        .or_else(|| params.get("position").and_then(|value| value.as_str()))
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        Some(value) => external_agent::RollbackAnchorPosition::from_str(value),
        None => Some(external_agent::RollbackAnchorPosition::After),
    }
}

fn is_context_rewind_action(action: &str) -> bool {
    matches!(
        action,
        "rewind_context"
            | "rewind-context"
            | "rewind-anchor"
            | "rewind_anchor"
            | "rewind-to-item"
            | "rewind_to_item"
            | "rollback-anchor"
            | "rollback_anchor"
            | "rollback-to-item"
            | "rollback_to_item"
    )
}

fn external_context_rewind_request_from_action(
    action: &str,
    params: &serde_json::Value,
    session_id: Option<String>,
) -> Option<Result<ExternalContextRewindRequest, String>> {
    if !is_context_rewind_action(action) {
        return None;
    }

    let item_id = match context_rewind_anchor_item_id(params) {
        Some(item_id) => item_id,
        None => {
            return Some(Err(
                "rewind_context requires anchor.item_id or itemId".to_string()
            ));
        }
    };
    let position = match context_rewind_anchor_position(params) {
        Some(position) => position,
        None => {
            return Some(Err(
                "rewind_context anchor.position must be `before` or `after`".to_string(),
            ));
        }
    };
    let is_model_rewind = matches!(action, "rewind_context" | "rewind-context");
    let reason = optional_trimmed_string(params, "reason");
    let primer = optional_trimmed_string(params, "primer");
    if is_model_rewind {
        if reason.is_none() {
            return Some(Err("rewind_context requires a non-empty reason".to_string()));
        }
        if primer.is_none() {
            return Some(Err("rewind_context requires a non-empty primer".to_string()));
        }
    }

    Some(Ok(ExternalContextRewindRequest {
        session_id,
        item_id,
        position,
        reason,
        primer,
        preserve: clean_context_rewind_list(params, "preserve"),
        discard: clean_context_rewind_list(params, "discard"),
        artifacts: clean_context_rewind_list(params, "artifacts"),
        next_steps: clean_context_rewind_list(params, "next_steps"),
        auto_resume: is_model_rewind,
        require_density_improvement: false,
        surgical: false,
    }))
}

fn backend_recovery_outcome_or_context_rewind(
    request: Option<ExternalContextRewindRequest>,
    turn_stop_status: ManagedContextRewindTurnStopStatus,
    recovery: Option<ExternalBackendRecovery>,
    message: Option<String>,
    turns_in_round: usize,
) -> DrainOutcome {
    if let Some(request) = request {
        return DrainOutcome::ContextRewindRequested {
            request,
            message,
            turns_in_round,
            turn_stop_status,
        };
    }
    if let Some(recovery) = recovery {
        return DrainOutcome::RecoveryRequired {
            message: recovery.message,
            recovery_hint: recovery.recovery_hint,
            turns_in_round,
        };
    }
    DrainOutcome::TurnCompleted {
        message,
        turns_in_round,
    }
}

fn recovery_required_message(message: &str, recovery_hint: Option<&str>) -> String {
    let mut out = format!("External agent recovery required after backend error: {message}");
    if let Some(hint) = recovery_hint.filter(|hint| !hint.trim().is_empty()) {
        out.push_str("\nRecovery: ");
        out.push_str(hint.trim());
    }
    out
}

fn resolve_context_rewind_anchor(
    source_rollout_path: &Path,
    requested_item_id: &str,
) -> Result<ResolvedContextRewindAnchor, String> {
    let requested_item_id = requested_item_id.trim();
    if requested_item_id.is_empty() {
        return Err("rewind anchor item id is required".to_string());
    }

    let anchor = find_context_rewind_anchor_entry(source_rollout_path, requested_item_id).map_err(
        |err| {
            format!(
                "failed to inspect rollout anchors in {}: {err}",
                source_rollout_path.display()
            )
        },
    )?;
    if anchor.is_none() {
        return Err(format!(
            "rollback anchor item_id `{requested_item_id}` was not found in {}; call list_rewind_anchors to inspect valid exact anchors before retrying",
            source_rollout_path.display()
        ));
    }

    Ok(ResolvedContextRewindAnchor::requested(requested_item_id))
}

fn context_rewind_anchor_prefix_estimate(
    anchor: &ContextRewindAnchorCatalogEntry,
    position: external_agent::RollbackAnchorPosition,
) -> Option<u64> {
    match position {
        external_agent::RollbackAnchorPosition::Before => {
            anchor.prefix_estimated_tokens_before_anchor
        }
        external_agent::RollbackAnchorPosition::After => {
            anchor.prefix_estimated_tokens_after_anchor
        }
    }
}

fn context_rewind_anchor_restore_usage_for_headroom(
    anchor: &ContextRewindAnchorCatalogEntry,
    position: external_agent::RollbackAnchorPosition,
) -> Option<(&'static str, u64, u64)> {
    let rewind_only_limit = anchor.rewind_only_limit_at_or_after_anchor?;
    if position == external_agent::RollbackAnchorPosition::After {
        if let Some(backend_tokens) = anchor.backend_usage_at_or_after_anchor {
            return Some(("backend-reported", backend_tokens, rewind_only_limit));
        }
    }
    let prefix_tokens = context_rewind_anchor_prefix_estimate(anchor, position)?;
    // A backend report that measured a strict prefix of the cut is a real
    // lower bound on the post-rewind context. Char-based prefix estimates
    // cannot see instructions or tool specs, so when the backend floor is
    // higher it is the honest eligibility input — otherwise an optimistic
    // estimate offers cuts that keep far more than the threshold allows.
    let backend_floor = anchor.backend_usage_before_anchor.unwrap_or(0);
    if backend_floor > prefix_tokens {
        return Some(("backend-reported", backend_floor, rewind_only_limit));
    }
    Some(("estimated", prefix_tokens, rewind_only_limit))
}

fn context_rewind_anchor_position_recovery_eligible(
    anchor: &ContextRewindAnchorCatalogEntry,
    position: external_agent::RollbackAnchorPosition,
    latest_outcome: Option<ContextRewindBackendUsageAtLine>,
) -> Option<bool> {
    let (_, used_tokens, rewind_only_limit) =
        context_rewind_anchor_restore_usage_for_headroom(anchor, position)?;
    if !context_rewind_anchor_has_recovery_headroom(used_tokens, rewind_only_limit) {
        return Some(false);
    }
    Some(latest_outcome.is_none_or(|outcome| {
        context_rewind_anchor_has_recovery_headroom(outcome.used_tokens, outcome.rewind_only_limit)
    }))
}

fn managed_context_density_recommended_limit(rewind_only_limit: u64) -> u64 {
    (rewind_only_limit as f64 * MANAGED_CONTEXT_DENSITY_THRESHOLD_PCT / 100.0).floor() as u64
}

fn context_rewind_anchor_has_density_headroom(used_tokens: u64, rewind_only_limit: u64) -> bool {
    used_tokens < managed_context_density_recommended_limit(rewind_only_limit)
}

fn context_rewind_anchor_position_density_eligible(
    anchor: &ContextRewindAnchorCatalogEntry,
    position: external_agent::RollbackAnchorPosition,
    latest_outcome: Option<ContextRewindBackendUsageAtLine>,
) -> Option<bool> {
    let (_, used_tokens, rewind_only_limit) =
        context_rewind_anchor_restore_usage_for_headroom(anchor, position)?;
    if !context_rewind_anchor_has_density_headroom(used_tokens, rewind_only_limit) {
        return Some(false);
    }
    Some(latest_outcome.is_none_or(|outcome| {
        context_rewind_anchor_has_density_headroom(outcome.used_tokens, outcome.rewind_only_limit)
    }))
}

fn validate_context_rewind_anchor_restore_headroom(
    source_rollout_path: &Path,
    requested_item_id: &str,
    position: external_agent::RollbackAnchorPosition,
) -> Result<(), String> {
    let requested_item_id = requested_item_id.trim();
    let Some(anchor) = find_context_rewind_anchor_entry(source_rollout_path, requested_item_id)
        .map_err(|err| {
            format!(
                "failed to inspect rollout anchors in {}: {err}",
                source_rollout_path.display()
            )
        })?
    else {
        return Ok(());
    };

    if let Some(start_line) = anchor.managed_context_recovery_start_line {
        return Err(format!(
            "rewind anchor item_id `{requested_item_id}` is inside the active managed-context recovery span that starts at rollout line {start_line}; choosing it would preserve the recovery kickstart prompt or its list/inspect calls. Call list_rewind_anchors again without include_non_recovery and choose an anchor before that managed-context recovery span."
        ));
    }

    let Some((usage_kind, used_tokens, rewind_only_limit)) =
        context_rewind_anchor_restore_usage_for_headroom(&anchor, position)
    else {
        return Ok(());
    };
    if context_rewind_anchor_has_recovery_headroom(used_tokens, rewind_only_limit) {
        // Prior-outcome veto is anchor-level (managed.md: an anchor that
        // already proved insufficient is not re-offered), so a failed rewind
        // at either position blocks both positions of the same anchor.
        for outcome_position in [
            position,
            match position {
                external_agent::RollbackAnchorPosition::Before => {
                    external_agent::RollbackAnchorPosition::After
                }
                external_agent::RollbackAnchorPosition::After => {
                    external_agent::RollbackAnchorPosition::Before
                }
            },
        ] {
            let Some(outcome) = latest_context_rewind_outcome_for_anchor(
                source_rollout_path,
                requested_item_id,
                outcome_position,
            )
            .map_err(|err| {
                format!(
                    "failed to inspect prior rewind outcomes in {}: {err}",
                    source_rollout_path.display()
                )
            })?
            else {
                continue;
            };
            if context_rewind_anchor_has_recovery_headroom(
                outcome.used_tokens,
                outcome.rewind_only_limit,
            ) {
                continue;
            }
            return Err(format!(
                "rewind anchor item_id `{requested_item_id}` is not a valid recovery target for position `{}`: a prior rewind to {} item was followed by {} tokens against the {} token rewind-only limit. Rows returned only with include_non_recovery=true are diagnostic and must not be passed to rewind_context. Call list_rewind_anchors again without include_non_recovery and choose an anchor whose positions includes the requested position; audit rows may expose recovery_eligible_positions.",
                position.as_str(),
                outcome_position.as_str(),
                outcome.used_tokens,
                outcome.rewind_only_limit
            ));
        }
        return Ok(());
    }

    Err(format!(
        "rewind anchor item_id `{requested_item_id}` is not a valid recovery target for position `{}`: restoring {} item would keep {} {} tokens before the injected primer, leaving less than {} normal-tool headroom under the {} token rewind-only limit. Rows returned only with include_non_recovery=true are diagnostic and must not be passed to rewind_context. Call list_rewind_anchors again without include_non_recovery and choose an anchor whose positions includes the requested position; audit rows may expose recovery_eligible_positions.",
        position.as_str(),
        position.as_str(),
        usage_kind,
        used_tokens,
        CONTEXT_REWIND_RECOVERY_MIN_RESUME_HEADROOM_TOKENS,
        rewind_only_limit
    ))
}

fn validate_context_rewind_anchor_density_improvement(
    source_rollout_path: &Path,
    requested_item_id: &str,
    position: external_agent::RollbackAnchorPosition,
) -> Result<(), String> {
    let requested_item_id = requested_item_id.trim();
    let Some(anchor) = find_context_rewind_anchor_entry(source_rollout_path, requested_item_id)
        .map_err(|err| {
            format!(
                "failed to inspect rollout anchors in {}: {err}",
                source_rollout_path.display()
            )
        })?
    else {
        return Ok(());
    };

    let Some((usage_kind, used_tokens, rewind_only_limit)) =
        context_rewind_anchor_restore_usage_for_headroom(&anchor, position)
    else {
        return Err(format!(
            "density handoff rewind anchor item_id `{requested_item_id}` cannot be validated for material density improvement at position `{}` because the rollout has no backend or prefix usage estimate for that position. Call list_rewind_anchors with density_candidates_only=true and include_pruning_estimates=true, choose an exact returned anchor/position, or reply with a concise no-rewind handoff and stop.",
            position.as_str()
        ));
    };
    let recommended_rewind_limit = managed_context_density_recommended_limit(rewind_only_limit);
    if context_rewind_anchor_has_density_headroom(used_tokens, rewind_only_limit) {
        if let Some(outcome) = latest_context_rewind_outcome_for_anchor(
            source_rollout_path,
            requested_item_id,
            position,
        )
        .map_err(|err| {
            format!(
                "failed to inspect prior rewind outcomes in {}: {err}",
                source_rollout_path.display()
            )
        })? {
            if context_rewind_anchor_has_density_headroom(
                outcome.used_tokens,
                outcome.rewind_only_limit,
            ) {
                return Ok(());
            }
            return Err(format!(
                "density handoff rewind anchor item_id `{requested_item_id}` is too shallow for position `{}`: a prior rewind to that exact item was followed by {} tokens, still at or above the recommended density threshold {} for the {} token context. Choose an exact item_id/position from list_rewind_anchors with density_candidates_only=true, or reply with a concise no-rewind handoff and stop.",
                position.as_str(),
                outcome.used_tokens,
                managed_context_density_recommended_limit(outcome.rewind_only_limit),
                outcome.rewind_only_limit,
            ));
        }
        return Ok(());
    }

    Err(format!(
        "density handoff rewind anchor item_id `{requested_item_id}` is too shallow for position `{}`: restoring {} item would keep {} tokens, still at or above the recommended density threshold {} for the {} token context. Choose an exact item_id/position from list_rewind_anchors with density_candidates_only=true, or reply with a concise no-rewind handoff and stop.",
        position.as_str(),
        usage_kind,
        used_tokens,
        recommended_rewind_limit,
        rewind_only_limit
    ))
}

fn context_rewind_thread_id_candidates(
    session_id: Option<&str>,
    alias_session_id: Option<&str>,
) -> Vec<String> {
    let mut ids = Vec::new();
    for id in [session_id, alias_session_id]
        .into_iter()
        .flatten()
        .map(str::trim)
        .filter(|id| !id.is_empty())
    {
        if !ids.iter().any(|existing| existing == id) {
            ids.push(id.to_string());
        }
    }
    ids
}

fn active_context_rewind_thread_ids(config: &DrainConfig<'_>) -> Vec<String> {
    context_rewind_thread_id_candidates(
        config.session_id.as_deref(),
        config.alias_session_id.as_deref(),
    )
}

async fn validate_context_rewind_request_before_schedule(
    agent: &mut Box<dyn external_agent::ExternalAgent>,
    thread_ids: &[String],
    request: &ExternalContextRewindRequest,
) -> Result<(), String> {
    if !agent.supports_item_anchor_rewind() {
        return Err(format!(
            "{} does not support item-anchor rewind",
            agent.name()
        ));
    }
    if thread_ids.is_empty() {
        return Err(
            "cannot validate context rewind: active Codex thread id is unknown".to_string(),
        );
    }

    let mut metadata_errors = Vec::new();
    for thread_id in thread_ids {
        match agent.read_thread_snapshot(thread_id).await {
            Ok(snapshot) => {
                let source_rollout_path = snapshot.rollout_path.ok_or_else(|| {
                    format!("thread metadata for {thread_id} did not include a rollout path")
                })?;
                resolve_context_rewind_anchor(&source_rollout_path, &request.item_id)?;
                validate_context_rewind_anchor_restore_headroom(
                    &source_rollout_path,
                    &request.item_id,
                    request.position,
                )?;
                if request.require_density_improvement {
                    validate_context_rewind_anchor_density_improvement(
                        &source_rollout_path,
                        &request.item_id,
                        request.position,
                    )?;
                }
                return Ok(());
            }
            Err(e) => metadata_errors.push(format!("{thread_id}: {e}")),
        }
    }

    Err(format!(
        "failed to read thread metadata before rewind for active thread candidates [{}]: {}",
        thread_ids.join(", "),
        metadata_errors.join("; ")
    ))
}

fn find_context_rewind_anchor_entry(
    source_rollout_path: &Path,
    requested_item_id: &str,
) -> io::Result<Option<ContextRewindAnchorCatalogEntry>> {
    Ok(scan_context_rewind_anchor_catalog(source_rollout_path)?
        .into_iter()
        .find(|anchor| anchor.item_id == requested_item_id))
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct RolloutUserTurn {
    index: u32,
    line: usize,
    text: String,
}

#[derive(Debug, Clone, PartialEq, Eq)]
struct ManagedContextEditBranchTarget {
    record_id: String,
    parent_thread_id: String,
    recovery_rollout_path: PathBuf,
    source_turn_count: u32,
    target_turn_text: String,
}

fn rollout_user_turns(rollout_path: &Path) -> io::Result<Vec<RolloutUserTurn>> {
    let file = std::fs::File::open(rollout_path)?;
    let reader = io::BufReader::new(file);
    let mut saw_user_message_event = false;
    let mut event_turns = Vec::new();
    let mut fallback_turns = Vec::new();

    for (line_index, line) in reader.lines().enumerate() {
        let line = line?;
        let Ok(entry) = serde_json::from_str::<serde_json::Value>(&line) else {
            continue;
        };
        match entry.get("type").and_then(|value| value.as_str()) {
            Some("event_msg") => {
                let Some(payload) = entry.get("payload") else {
                    continue;
                };
                match payload.get("type").and_then(|value| value.as_str()) {
                    Some("user_message") => {
                        saw_user_message_event = true;
                        if let Some(text) = payload
                            .get("message")
                            .and_then(|value| value.as_str())
                            .filter(|text| !is_codex_injected_user_text_for_main(text))
                        {
                            push_rollout_user_turn(
                                &mut event_turns,
                                line_index.saturating_add(1),
                                text.to_string(),
                            );
                        }
                    }
                    Some("thread_rolled_back") => {
                        let turns_to_drop = payload
                            .get("num_turns")
                            .and_then(|value| value.as_u64())
                            .unwrap_or(0) as u32;
                        truncate_rollout_user_turns(&mut event_turns, turns_to_drop);
                        truncate_rollout_user_turns(&mut fallback_turns, turns_to_drop);
                    }
                    _ => {}
                }
            }
            Some("response_item") => {
                let Some(payload) = entry.get("payload") else {
                    continue;
                };
                if let Some(text) = codex_payload_user_text(payload) {
                    push_rollout_user_turn(&mut fallback_turns, line_index.saturating_add(1), text);
                }
            }
            _ => {}
        }
    }

    Ok(if saw_user_message_event {
        event_turns
    } else {
        fallback_turns
    })
}

fn push_rollout_user_turn(turns: &mut Vec<RolloutUserTurn>, line: usize, text: String) {
    turns.push(RolloutUserTurn {
        index: turns.len().saturating_add(1) as u32,
        line,
        text,
    });
}

fn truncate_rollout_user_turns(turns: &mut Vec<RolloutUserTurn>, turns_to_drop: u32) {
    if turns_to_drop == 0 || turns.is_empty() {
        return;
    }
    let keep = turns.len().saturating_sub(turns_to_drop as usize);
    turns.truncate(keep);
}

fn managed_context_edit_record_dirs(
    log_dir: &Path,
    thread_id: &str,
    session_id: Option<&str>,
) -> Vec<PathBuf> {
    let mut dirs = Vec::new();
    let mut seen = HashSet::new();
    let mut push_dir = |path: PathBuf| {
        if !path.is_dir() {
            return;
        }
        let key = std::fs::canonicalize(&path)
            .unwrap_or_else(|_| path.clone())
            .to_string_lossy()
            .to_string();
        if seen.insert(key) {
            dirs.push(path);
        }
    };

    push_dir(log_dir.to_path_buf());
    let Some(home) = external_wrapper_index::home_from_log_dir(log_dir) else {
        return dirs;
    };

    let ids = [Some(thread_id), session_id];
    for id in ids
        .into_iter()
        .flatten()
        .map(str::trim)
        .filter(|id| !id.is_empty())
    {
        push_dir(home.join(".intendant").join("logs").join(id));
        for record in external_wrapper_index::wrappers_for(&home, "codex", id) {
            push_dir(PathBuf::from(record.log_path));
        }
    }

    let logs_dir = home.join(".intendant").join("logs");
    if let Ok(entries) = std::fs::read_dir(logs_dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() && context_rewind::records_dir(&path).is_dir() {
                push_dir(path);
            }
        }
    }

    dirs
}

fn managed_context_edit_records(
    log_dir: &Path,
    thread_id: &str,
    session_id: Option<&str>,
) -> Result<Vec<context_rewind::ContextRewindRecord>, String> {
    let mut records = Vec::new();
    let mut seen = HashSet::new();
    for dir in managed_context_edit_record_dirs(log_dir, thread_id, session_id) {
        let mut from_dir = context_rewind::list_records(&dir).map_err(|err| {
            format!(
                "failed to list managed-context rewind records in {}: {err}",
                dir.display()
            )
        })?;
        from_dir.retain(|record| {
            record.thread_id == thread_id
                || session_id
                    .is_some_and(|session_id| record.session_id.as_deref() == Some(session_id))
        });
        for record in from_dir {
            let key = format!(
                "{}\0{}\0{}",
                record.record_id,
                record.thread_id,
                record
                    .recovery_rollout_path
                    .as_ref()
                    .map(|path| path.to_string_lossy().to_string())
                    .unwrap_or_default()
            );
            if seen.insert(key) {
                records.push(record);
            }
        }
    }
    records.sort_by(|a, b| b.created_at.cmp(&a.created_at));
    Ok(records)
}

fn managed_context_edit_text_matches(recorded: &str, original: Option<&str>) -> bool {
    let Some(original) = original.map(str::trim).filter(|text| !text.is_empty()) else {
        return true;
    };
    recorded.trim() == original
}

fn resolve_managed_context_edit_branch_target(
    log_dir: &Path,
    thread_id: &str,
    session_id: Option<&str>,
    user_turn_index: u32,
    original_text: Option<&str>,
) -> Result<Option<ManagedContextEditBranchTarget>, String> {
    if user_turn_index == 0 {
        return Ok(None);
    }
    let records = managed_context_edit_records(log_dir, thread_id, session_id)?;
    let mut text_mismatches = Vec::new();

    for record in records {
        let matches_thread = record.thread_id == thread_id
            || session_id
                .is_some_and(|session_id| record.session_id.as_deref() == Some(session_id));
        if !matches_thread {
            continue;
        }
        let Some(recovery_rollout_path) = record.recovery_rollout_path.as_deref() else {
            continue;
        };
        let turns = rollout_user_turns(recovery_rollout_path).map_err(|err| {
            format!(
                "failed to inspect archived rollout for rewind record {}: {err}",
                record.record_id
            )
        })?;
        let Some(turn) = turns.get(user_turn_index.saturating_sub(1) as usize) else {
            continue;
        };
        if !managed_context_edit_text_matches(&turn.text, original_text) {
            text_mismatches.push(record.record_id.clone());
            continue;
        }
        return Ok(Some(ManagedContextEditBranchTarget {
            record_id: record.record_id,
            parent_thread_id: record.thread_id,
            recovery_rollout_path: recovery_rollout_path.to_path_buf(),
            source_turn_count: turns.len() as u32,
            target_turn_text: turn.text.clone(),
        }));
    }

    if !text_mismatches.is_empty() {
        return Err(format!(
            "found archived managed-context rollout(s) containing user turn {}, but none matched the clicked message text; refusing to branch from an ambiguous stale edit",
            user_turn_index
        ));
    }
    Ok(None)
}

#[derive(Debug, Clone, Serialize)]
struct ContextRewindAnchorCatalogEntry {
    ordinal: usize,
    item_id: String,
    first_line: usize,
    last_line: usize,
    first_item_type: String,
    last_item_type: String,
    /// Whether the anchor's last item was emitted by the model (assistant
    /// message, reasoning, tool *call*) rather than appended by the runtime
    /// (tool *output*, user/developer message). Model-emitted items are
    /// covered by their own response's token report; runtime-appended items
    /// are only covered by a report from a *later* model response.
    #[serde(skip_serializing)]
    last_item_is_model: bool,
    positions: Vec<&'static str>,
    position_hint: &'static str,
    #[serde(skip_serializing_if = "Vec::is_empty")]
    names: Vec<String>,
    #[serde(skip_serializing_if = "Vec::is_empty")]
    roles: Vec<String>,
    summary: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    backend_usage_at_or_after_anchor: Option<u64>,
    /// Last backend report that measured a strict prefix of this anchor
    /// (its response began at or before the anchor's first line). Real
    /// lower bound for what any cut keeping this anchor's prefix retains;
    /// char-based prefix estimates understate because they cannot see
    /// instructions or tool specs.
    #[serde(skip_serializing_if = "Option::is_none")]
    backend_usage_before_anchor: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    rewind_only_limit_at_or_after_anchor: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    recommended_rewind_limit_at_or_after_anchor: Option<u64>,
    #[serde(skip_serializing)]
    prefix_estimated_tokens_before_anchor: Option<u64>,
    #[serde(skip_serializing)]
    prefix_estimated_tokens_after_anchor: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    approx_pruned_tokens_before: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    approx_pruned_tokens_after: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    prefix_tokens_after: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    latest_rewind_usage_after_anchor: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    latest_rewind_limit_after_anchor: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    recovery_eligible: Option<bool>,
    #[serde(skip_serializing_if = "Option::is_none")]
    recovery_eligible_positions: Option<Vec<&'static str>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    density_eligible: Option<bool>,
    #[serde(skip_serializing_if = "Option::is_none")]
    density_eligible_positions: Option<Vec<&'static str>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    managed_context_recovery_start_line: Option<usize>,
}

#[derive(Debug, Clone, Serialize)]
struct ContextRewindAnchorCompactEntry {
    ordinal: usize,
    item_id: String,
    item_type: String,
    positions: Vec<&'static str>,
    position_hint: &'static str,
    #[serde(skip_serializing_if = "Vec::is_empty")]
    names: Vec<String>,
    #[serde(skip_serializing_if = "Vec::is_empty")]
    roles: Vec<String>,
    summary: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    density_eligible_positions: Option<Vec<&'static str>>,
    #[serde(skip_serializing_if = "Option::is_none")]
    approx_pruned_tokens_before: Option<u64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    approx_pruned_tokens_after: Option<u64>,
}

#[derive(Debug, Clone, Serialize)]
struct ContextRewindAnchorCatalog {
    total: usize,
    filtered_total: usize,
    offset: usize,
    limit: usize,
    next_offset: Option<usize>,
    query: Option<String>,
    include_management_tools: bool,
    include_non_recovery: bool,
    recovery_candidates_only: bool,
    density_candidates_only: bool,
    pruning_estimates_included: bool,
    anchors: Vec<ContextRewindAnchorCatalogEntry>,
}

#[derive(Debug, Clone, Serialize)]
struct ContextRewindAnchorCompactCatalog {
    catalog_format: &'static str,
    total: usize,
    filtered_total: usize,
    offset: usize,
    limit: usize,
    next_offset: Option<usize>,
    output_cap_bytes: usize,
    output_truncated: bool,
    query: Option<String>,
    include_management_tools: bool,
    include_non_recovery: bool,
    recovery_candidates_only: bool,
    density_candidates_only: bool,
    pruning_estimates_included: bool,
    /// True when this is a re-listing of the default page inside one
    /// managed-context stall: the rows are unchanged, so the model should
    /// commit instead of listing again.
    #[serde(skip_serializing_if = "Option::is_none")]
    repeat_listing: Option<bool>,
    /// True when the eligible catalog itself is empty: no anchor remains
    /// that a rewind could legally target.
    #[serde(skip_serializing_if = "Option::is_none")]
    no_eligible_anchors: Option<bool>,
    /// Set with an empty page to say why it is empty
    /// (`no_eligible_anchors`, `query_unmatched`, `offset_past_end`).
    #[serde(skip_serializing_if = "Option::is_none")]
    empty_page_reason: Option<&'static str>,
    /// Plain-language direction for the repeat/empty cases above.
    #[serde(skip_serializing_if = "Option::is_none")]
    notice: Option<String>,
    anchors: Vec<ContextRewindAnchorCompactEntry>,
}

