    #[test]
    fn model_checkpoint_flushes_pending_runtime_steers() {
        let bus = EventBus::new();
        let mut rx = bus.subscribe();
        let mut pending = std::collections::VecDeque::from([
            PendingRuntimeSteer {
                session_id: Some("codex-thread".to_string()),
                id: "steer-1".to_string(),
                text: "first steer".to_string(),
            },
            PendingRuntimeSteer {
                session_id: Some("codex-thread".to_string()),
                id: "steer-2".to_string(),
                text: "second steer".to_string(),
            },
        ]);

        let delivered = flush_pending_runtime_steers_for_model_checkpoint(
            &bus,
            &mut pending,
            &Some("codex-thread".into()),
        );

        assert_eq!(delivered, 2);
        assert!(pending.is_empty());

        let mut ids = Vec::new();
        while let Ok(ev) = rx.try_recv() {
            match ev {
                AppEvent::SteerDelivered {
                    session_id,
                    id,
                    mid_turn,
                } => {
                    assert_eq!(session_id.as_deref(), Some("codex-thread"));
                    assert!(mid_turn);
                    ids.push(id);
                }
                other => panic!("expected SteerDelivered, got {:?}", other),
            }
        }
        assert_eq!(ids, vec!["steer-1".to_string(), "steer-2".to_string()]);
    }

    // ---- fission supervisor core ----

    fn fission_test_drain_config<'a>(
        bus: &'a EventBus,
        session_log: &'a SharedSessionLog,
        approval_registry: &'a event::ApprovalRegistry,
        context_injection: &'a event::ContextInjectionQueue,
        project_root: &'a Path,
        log_dir: &'a Path,
        session_id: &str,
    ) -> DrainConfig<'a> {
        DrainConfig {
            bus,
            web_port: None,
            session_id: Some(session_id.to_string()),
            alias_session_id: None,
            backend_thread_id: Some(session_id.to_string()),
            autonomy: autonomy::shared_autonomy(AutonomyState::default()),
            session_log,
            project_root,
            log_dir,
            approval_registry,
            json_approval: None,
            agent_source: Some("Codex".to_string()),
            suppress_agent_started: true,
            persist_model_responses_inline: false,
            headless: true,
            context_injection,
        }
    }

    /// Write a synthetic Codex rollout: one `function_call` response item per
    /// `(call_id, name)` pair, one rollout line each.
    fn write_fission_test_rollout(path: &Path, items: &[(&str, &str)]) {
        let mut out = String::new();
        for (call_id, name) in items {
            out.push_str(
                &serde_json::json!({
                    "type": "response_item",
                    "payload": {
                        "type": "function_call",
                        "call_id": call_id,
                        "name": name,
                        "arguments": "{}",
                    }
                })
                .to_string(),
            );
            out.push('\n');
        }
        std::fs::write(path, out).unwrap();
    }

    fn init_fission_test_git_repo(root: &Path) {
        let run = |args: &[&str]| {
            let output = std::process::Command::new("git")
                .args(args)
                .current_dir(root)
                .output()
                .unwrap();
            assert!(
                output.status.success(),
                "git {:?} failed: {}",
                args,
                String::from_utf8_lossy(&output.stderr)
            );
        };
        run(&["init"]);
        run(&["config", "user.email", "test@test.com"]);
        run(&["config", "user.name", "Test"]);
        std::fs::write(root.join("README.md"), "# fission test\n").unwrap();
        run(&["add", "README.md"]);
        run(&["commit", "-m", "initial"]);
    }

